INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/15/allbirds-stock-ai-pivot', 'Shares in Allbirds surge after maker of wool sneakers announces pivot to AI', '2026-04-15T21:00:47+00:00', '<p>Rebrand as NewBird AI sent shares up 582% in bizarre and rapid turnaround for firm that had fallen on hard times</p><p>Allbirds, the maker of minimalist wool sneakers beloved by Silicon Valley, announced on Wednesday that it is leaving shoes behind and pivoting to artificial intelligence. The new focus and rebrand as “NewBird AI” sent the company’s stock up 582% as of mid-day during a flurry of trading.</p><p>The surging stock price and new direction is a bizarre, rapid turnaround for a company that had fallen into disrepair in recent years. Once valued at $4bn, Allbirds’ shares had lost 99% of their worth since 2021 and earlier this month <a href="https://www.theguardian.com/business/2026/apr/02/eco-shoe-brand-allbirds-sold-american-exchange-group">the company announced plans for a $39m sale</a> to brand management firm American Exchange Company.</p> <a href="https://www.theguardian.com/business/2026/apr/15/allbirds-stock-ai-pivot">Continue reading...</a>', '2026-04-16T01:02:37-05:00', 32460000);
