INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/16/yesteryear-by-caro-claire-burke-review-the-downfall-of-an-allamerican-tradwife', 'Yesteryear by Caro Claire Burke review – the downfall of an all‑American tradwife', '2026-04-16T06:00:51+00:00', '<p>The premise – Instagram influencer is confronted by pioneer reality – is genius. But does this high-concept debut live up to the hype?</p><p>Could Caro Claire Burke’s Yesteryear be the first great tradwife novel? This was my hope: finally, a literary response to the&nbsp;unhinged social trend of women cosplaying “traditional Christian values” – pronatalism and obeying one’s husband – to large social media followings. I am not immune to hype, and Yesteryear has been hyped to high heaven, prompting massive auctions for the rights, and landing a film deal with Anne Hathaway.</p><p>You have to admit that the premise – Instagram tradwife wakes up in what&nbsp;appear to be the actual pioneer days, and finds that traditional wifedom is not as much of a hoot as&nbsp;her&nbsp;whitewashed social media re-enactment had implied – is genius. As one of the “Angry Women” our heroine Natalie so disparages, I was looking forward to some sweet schadenfreude.</p> <a href="https://www.theguardian.com/books/2026/apr/16/yesteryear-by-caro-claire-burke-review-the-downfall-of-an-allamerican-tradwife">Continue reading...</a>', '2026-04-16T01:08:52-05:00', 480000);
