INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/football/2026/apr/16/ticket-to-ride-america-2026-world-cup-actively-hates-you', 'Ticket to ride? Fifa premium makes this the World Cup that actively hates you | Jonathan Liew', '2026-04-16T07:00:52+00:00', '<p>The $95 bus trip to Foxborough highlights a tournament unique in modern times – one that ultimately makes no secret of its disdain for the paying public</p><p>Like any journalist with an unerring nose for an offbeat feature, my interest was sharply piqued by this week’s <a href="https://www.theguardian.com/football/2026/apr/14/nj-transit-train-tickets-prices-new-york-world-cup">announcement of the $95 bus ride</a>. What magnificent accoutrements might conceivably justify the £70 fare for a half-hour journey from south Boston to Foxborough? An at-seat shiatsu? A pool deck? A five-course dining experience? A brief but moving Céline Dion set in the aisles? At the very least, I felt I owed it to my profession to find out for sure.</p><p>Alas upon closer investigation, the Boston Stadium Express being launched for this summer’s World Cup appears to be an entirely regular bus journey on an entirely regular bus with entirely regular bus seats. Your non-refundable ticket – no child concessions – entitles you simply to be dropped off a 15-minute walk from the ground, and picked up again from the same place. There is, in short, no more complex rationale for the Boston organising committee to charge £70 than the fact that they can, and the World Cup only comes once, and if you don’t want to pay then some other rube will.</p> <a href="https://www.theguardian.com/football/2026/apr/16/ticket-to-ride-america-2026-world-cup-actively-hates-you">Continue reading...</a>', '2026-04-16T02:18:59-05:00', 1086000);
