INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/14/ai-productivity-workplace-errors', 'Bosses say AI boosts productivity – workers say they’re drowning in ‘workslop’', '2026-04-14T14:00:58+00:00', '<p>Workslop refers to AI-generated work that seems polished but is flawed and in need of heavy corrections</p><p>Ken, a copywriter for a large, Miami-based cybersecurity firm, used to enjoy his job. But then the “workslop” started piling up.</p><p><a href="https://www.betterup.com/workslop">Workslop</a> is an unintended consequence of the AI boom. It’s what happens when employees use AI to quickly generate work that <em>seems</em> polished – at least superficially – but is in fact so flawed or inaccurate that it needs to be heavily corrected, cleaned up or even completely redone after it’s passed on to colleagues.</p> <a href="https://www.theguardian.com/technology/2026/apr/14/ai-productivity-workplace-errors">Continue reading...</a>', '2026-04-16T02:22:10-05:00', 147600000);
