INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/global-development/2026/apr/16/eliminate-malaria-eswatini-swaziland-migration-disease-climate', 'Can you stop malaria crossing borders? One nation’s bid to wipe out the disease', '2026-04-16T04:00:47+00:00', '<p>Informal migration, plus climate change and rising numbers of cases globally, are complicating the tireless efforts of landlocked Eswatini to eradicate the killer disease</p><p>The freezer is filled with blue-lidded tubes of cows’ blood, ready to be defrosted and used to feed the colony of mosquitoes. “Also, you can use your arm,” says Nombuso Princess Bhembe, who tends the mosquitoes at Eswatini’s national insectary, an unremarkable building in the town of Siphofaneni, part of the southern African country’s push to eliminate malaria.</p><p>But the landlocked nation of 1.2 million people, formerly known as Swaziland, is facing headwinds from not only the climate crisis, aid cuts and insecticide resistance but also economic migration from countries with higher case numbers.</p> <a href="https://www.theguardian.com/global-development/2026/apr/16/eliminate-malaria-eswatini-swaziland-migration-disease-climate">Continue reading...</a>', '2026-04-16T02:24:15-05:00', 12180000);
