INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/science/audio/2026/apr/16/the-surprising-value-of-boring-chats-super-el-nino-and-alzheimers-evidence-reviewed-podcast', 'The surprising value of boring chats, ‘super El Niño’ and Alzheimer’s evidence reviewed – podcast', '2026-04-16T04:00:48+00:00', '<p>Madeleine Finlay sits down with co-host and science editor Ian Sample to discuss three eye-catching stories from the week, including a review into the effectiveness of a new class of Alzheimer’s drug that was once hailed as a game-changer in slowing the progress of the disease. Also on the agenda is the news that the world could be heading for a ‘super El Niño’ this summer and a study exploring whether conversations about dull topics really are as boring as we expect them to be</p><p><strong><a href="https://www.theguardian.com/science/2026/apr/13/hate-small-talk-enjoy-dull-chat-more-than-you-think">Hate small talk? You may enjoy that ‘dull’ chat more than you think, say researchers</a></strong></p><p>Support the Guardian: <a href="http://theguardian.com/sciencepod">theguardian.com/sciencepod</a></p> <a href="https://www.theguardian.com/science/audio/2026/apr/16/the-surprising-value-of-boring-chats-super-el-nino-and-alzheimers-evidence-reviewed-podcast">Continue reading...</a>', '2026-04-16T02:24:15-05:00', 12180000);
