INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/14/amazon-globalstar-satellite-deal-musk-starlink', 'Amazon to buy satellite firm Globalstar for $11.57bn in challenge to Musk’s Starlink', '2026-04-14T16:20:48+00:00', '<p>Deal, subject to regulatory approval, would give Bezos firm access to Globalstar’s network of two dozen satellites</p><p>Amazon said on Tuesday it would acquire a satellite company in an $11.57bn deal, bolstering its own fledgling space business as it looks to take on Elon Musk-led bigger rival Starlink.</p><p>The deal gives Amazon access to Globalstar’s network of two dozen satellites, boosting the tech giant’s ambitions to challenge SpaceX unit Starlink, which currently has about 10,000 units in orbit.</p> <a href="https://www.theguardian.com/technology/2026/apr/14/amazon-globalstar-satellite-deal-musk-starlink">Continue reading...</a>', '2026-04-16T02:24:15-05:00', 140400000);
