INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/14/african-scientists-fungal-conservation-movement-aoe', '‘Without them there is no life’: the race to understand the mysterious world of Africa’s fungi', '2026-04-14T04:00:02+00:00', '<p>Amid growing evidence of fungi’s key role in ecosystems and storing carbon, African scientists are championing the need to preserve ‘funga’ as much as flora and fauna</p><p>Madagascar has long been celebrated for its remarkable wildlife, with the vast majority of its species – from ring-tailed lemurs to certain species of baobab trees – found nowhere else on the planet. But when discussing the island nation’s endemic treasures, fungi are often left out of the conversation.</p><p>Yet “fungi are some of the most important things in the world”, says <a href="https://www.kew.org/read-and-watch/madagascar-mycologist-iwd">Anna Ralaiveloarisoa</a>, a Malagasy <a href="https://www.kew.org/read-and-watch/madagascar-mycologist-iwd">scientist</a>. “They feed 90% of terrestrial plants. Without them, there is no life on the Earth.”</p> <a href="https://www.theguardian.com/environment/2026/apr/14/african-scientists-fungal-conservation-movement-aoe">Continue reading...</a>', '2026-04-16T02:26:21-05:00', 183600000);
