INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/science/audio/2026/apr/14/helium-the-invisible-gas-that-powers-ai-and-why-its-in-short-supply-podcast', 'Helium: the invisible gas that powers AI, and why it’s in short supply – podcast', '2026-04-14T04:00:03+00:00', '<p>Alongside the oil and gas stranded in the strait of Hormuz is another commodity vital to today’s economy: helium. It is a critical element in all kinds of areas from MRI machines to the Large Hadron Collider, and even deep-sea diving. It is also integral to the AI boom. And this isn’t the first time its fragile global supply chain has been threatened. So why is helium so useful, and what will happen if the shortage continues? Ian Sample hears from co-host Madeleine Finlay, and from Sophia Hayes, professor of chemistry at Washington University in St. Louis</p><p><em>Clips: CBC</em></p><p>Support the Guardian: <a href="http://theguardian.com/sciencepod">theguardian.com/sciencepod</a></p> <a href="https://www.theguardian.com/science/audio/2026/apr/14/helium-the-invisible-gas-that-powers-ai-and-why-its-in-short-supply-podcast">Continue reading...</a>', '2026-04-16T02:26:21-05:00', 183600000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/15/critical-atlantic-current-significantly-more-likely-to-collapse-than-thought', 'Critical Atlantic current significantly more likely to collapse than thought', '2026-04-15T18:00:34+00:00', '<p>Scientists say finding is ‘very concerning’ as collapse would be catastrophic for Europe, Africa and the Americas</p><p>The critical Atlantic current system appears significantly more likely to collapse than previously thought after new research found that climate models predicting the biggest slowdown are the most realistic. Scientists called the new finding “very concerning” as a collapse would have catastrophic consequences for Europe, Africa and the Americas.</p><p>The Atlantic meridional overturning circulation (Amoc) is a major part of the global climate system and was already known to be at its <a href="https://www.theguardian.com/environment/2018/apr/11/critical-gulf-stream-current-weakest-for-1600-years-research-finds">weakest for 1,600 years</a> as a result of the climate crisis. Scientists spotted <a href="https://www.theguardian.com/environment/2021/aug/05/climate-crisis-scientists-spot-warning-signs-of-gulf-stream-collapse">warning signs of a tipping point</a> in 2021 and know that the Amoc has collapsed in the Earth’s past.</p> <a href="https://www.theguardian.com/environment/2026/apr/15/critical-atlantic-current-significantly-more-likely-to-collapse-than-thought">Continue reading...</a>', '2026-04-16T02:28:29-05:00', 48420000);
