INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/15/sperm-whales-alphabet-vocalizations-similar-humans', 'Sperm whales’ communication closely parallels human language, study finds', '2026-04-15T10:00:25+00:00', '<p>Analysis shows whales’ coda vocalizations are ‘highly complex’ and remarkably similar to our own</p><p>We may appear to have little in common with sperm whales – enormous, ocean-dwelling animals that last shared a common ancestor with humans more than 90 million years ago. But the whales’ vocalized communications are remarkably similar to our own, researchers have discovered.</p><p>Not only do sperm whale have a form of “<a href="https://www.projectceti.org/blog-posts/sperm-whale-phonetic-alphabet-proposed-for-the-first-time?gad_source=1&amp;gad_campaignid=13463846785&amp;gbraid=0AAAAABaEHBcjczDZrALBGM7x5x3b47ze7&amp;gclid=Cj0KCQjwy_fOBhC6ARIsAHKFB79TG9udro3bsQ8KH-szU20vsZUp2_KSaWndeWruCNFvjESTx86NdMkaAunzEALw_wcB">alphabet</a>” and form vowels within their vocalizations but the structure of these vowels behaves in the same way as human speech, the new study has found.</p> <a href="https://www.theguardian.com/environment/2026/apr/15/sperm-whales-alphabet-vocalizations-similar-humans">Continue reading...</a>', '2026-04-16T02:29:33-05:00', 77340000);
