INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/games/2026/apr/16/pragmata-review-playstation-5', 'Pragmata review – soulful sad dad saga in stunning outer space', '2026-04-16T07:30:51+00:00', '<p><strong>PlayStation 5 (version tested), Xbox, PC, Switch 2; Capcom<br></strong>Engineer Hugh is sent from Earth to investigate a malfunctioning research station and meets a young android who helps him fend off murderous mechs</p><p>When Pragmata was announced alongside the PlayStation 5 in 2020, its shiny trailer promised slick sci-fi action in outer space. While it certainly delivers those futuristic thrills in spades, what I <em>didn’t </em>expect was a tender tale of paternal love. This is Capcom’s belated, surprisingly soulful first entry into gaming’s sad dad genre.</p><p>In this near-future fiction, a corporation named Delphi has established a research station on the moon’s surface to experiment with advanced 3D printing tech, using “Lunafilament” to easily recreate everything from tools to entire buildings. Predictably, things soon go very wrong. As the station suddenly goes dark, engineer Hugh is sent from Earth to investigate.</p><p>Pragmata is out April 17; £49.99</p> <a href="https://www.theguardian.com/games/2026/apr/16/pragmata-review-playstation-5">Continue reading...</a>', '2026-04-16T02:39:06-05:00', 492000);
