INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/lifeandstyle/ng-interactive/2026/apr/16/wilding-newport-wales-grand-department-store-became-illicit-cannabis-farm', 'Wildings in Newport, Wales: the grand department store that became an illicit cannabis farm', '2026-04-16T09:00:54+00:00', '<p>For decades, Wildings was the poshest shop in town. But since it closed down in 2019, the storied building has fallen into disrepair and been commandeered as a drug den and a skate park. What happened?</p><p>I’m standing outside a lift in a department store in Newport, Wales, looking at the sign, wondering where to go. Stay on the ground floor for shoes, giftware and presents, ladies’ accessories and Estée Lauder? Or up to the first floor for furniture and ladies’ fashions – Annabelle, Tigi-Wear, Autonomy? It’s the second floor for cookshop and homeware. Lingerie is on three, plus Alfred’s coffee shop and tea room. Maybe I’ll go straight there for a cappuccino and a ponder …</p><p>But nothing happens when I press the button. The panel is hanging from the wall by its wires and doesn’t look safe. I’d be nervous about stepping into this lift. Plus, it’s dark. I’m using the torch on my phone to read the sign. There’s no giftware on this floor, no presents, no cosmetics counter. Once, this floor would have smelled of perfume; now, it’s musty, cold and empty. Because, on 19 January 2019, after 144 years of trading, this department store, Wildings, closed its doors for ever.</p> <a href="https://www.theguardian.com/lifeandstyle/ng-interactive/2026/apr/16/wilding-newport-wales-grand-department-store-became-illicit-cannabis-farm">Continue reading...</a>', '2026-04-16T04:50:06-05:00', 2952000);
