INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/16/mscs-blue-tick-scheme-creates-illusion-of-ethically-sourced-fish-study-claims', 'MSC’s ‘blue tick’ scheme creates illusion of ethically sourced fish, study claims', '2026-04-16T11:00:57+00:00', '<p>Sustainability certification by Marine Stewardship Council may be obscuring labour abuses in seafood supply chains, say researchers</p><p>The Marine Stewardship Council (MSC), which operates a “blue tick” scheme to indicate the sustainability of fish, has been accused of creating an “illusion” of ethical sourcing, after a <a href="https://www.itfglobal.org/en/resources/labour-abuses-in-msc-certified-fisheries">study reported</a> that widespread labour abuses have taken place on the fishing vessels it approves.</p><p>One in five vessels where the crew reported abuses to the International Transport Workers’ Federation (ITF) over the last five years took place on ships catching seafood certified as sustainable by the MSC, researchers found.</p> <a href="https://www.theguardian.com/environment/2026/apr/16/mscs-blue-tick-scheme-creates-illusion-of-ethically-sourced-fish-study-claims">Continue reading...</a>', '2026-04-16T06:08:48-05:00', 474000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/gallery/2026/apr/16/in-the-footsteps-of-linnaeus-scientists-share-their-passion-for-species-from-tiny-wasps-to-hairy-plants-in-pictures', 'In the footsteps of Linnaeus: scientists share their passion for species from tiny wasps to hairy plants – in pictures', '2026-04-16T11:00:56+00:00', '<p>For his project <a href="https://www.christerbphoto.com/de-ofortrutna/">‘De Oförtrutna’</a> (The Relentless), photographer <strong>Christer Björkman</strong> pictured Swedish scientists working in the spirit of <a href="https://www.theguardian.com/commentisfree/2014/jun/13/wikipedia-influence-list-carl-linnaeus">Carl Linnaeus</a>, the botanist who created the modern taxonomic system that classifies organisms based on appearance. Each scientist brought to the shoot a book and an item of importance to their work</p> <a href="https://www.theguardian.com/environment/gallery/2026/apr/16/in-the-footsteps-of-linnaeus-scientists-share-their-passion-for-species-from-tiny-wasps-to-hairy-plants-in-pictures">Continue reading...</a>', '2026-04-16T06:08:48-05:00', 474000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/global-development/2026/apr/16/norways-state-telecoms-firm-accused-of-helping-myanmar-regime-seize-activists', 'Norway’s state telecoms firm accused of helping Myanmar regime seize activists', '2026-04-16T09:00:53+00:00', '<p>Lawsuit in Norway alleges Telenor passed on data helping Myanmar military arrest 1,200 activists, some in safe houses</p><p>When even two weeks of torture could not force Aung Thu to betray his fellow anti-coup activists, his military interrogators in Myanmar tried something different: they asked a Norwegian telecoms company, Telenor, then the largest one operating in the country, for its data on him.</p><p>The company – whose majority shareholder is the Norwegian government – had first entered Myanmar in 2013 as it was transitioning to democracy, promising to connect users who had been isolated from the world.</p> <a href="https://www.theguardian.com/global-development/2026/apr/16/norways-state-telecoms-firm-accused-of-helping-myanmar-regime-seize-activists">Continue reading...</a>', '2026-04-16T06:09:53-05:00', 7740000);
