INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/14/all-them-dogs-by-djamel-white-review-murderous-desires-in-the-badlands-of-dublin', 'All Them Dogs by Djamel White review – murderous desires in the badlands of Dublin', '2026-04-14T08:00:04+00:00', '<p>Sparks fly in this homoerotic dance of desire and betrayal, from a powerful new voice in Irish literature</p><p>Toxic masculinity, that repressed and repressive male energy that does so much to fuel brutality and abuse, sometimes finds itself on the brink of a vulnerable homoeroticism. In Djamel White’s debut novel All Them Dogs, a vividly propulsive neo-noir, two violent men discover that murderous desires can lead to love as well as death. This is a fast-paced crime thriller with a psychosexual twist, set in a dangerously Freudian arena of Eros and Thanatos.</p><p>On the run for five years after killing a man in a gang fight, Tony Ward has returned to the badlands of west Dublin under the protection of a local crime boss. Teamed up with tall and sullen enforcer Darren “Flute” Walsh, Tony is back on his home turf grafting a grim routine of collecting debts and drug dealer’s dues. Propelled through a world of old scores and hard knocks, our protagonist is a shark who has to keep moving simply to survive. But when he and Flute are called upon to kill a failing dealer, their brutal conspiracy becomes a visceral dance of desire and betrayal.</p> <a href="https://www.theguardian.com/books/2026/apr/14/all-them-dogs-by-djamel-white-review-murderous-desires-in-the-badlands-of-dublin">Continue reading...</a>', '2026-04-16T08:48:16-05:00', 190800000);
