INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/16/the-possibility-of-tenderness-by-jason-allen-paisant-audiobook-review-meditations-on-nature-and-belonging', 'The Possibility of Tenderness by Jason Allen-Paisant audiobook review – meditations on nature and belonging', '2026-04-16T14:01:02+00:00', '<p>The poet reconnects with the landscape of the May Day Mountains in Jamaica where he grew up in a personal story of migration, race and rural life</p><p>An award-winning poet living in Roundhay Park, Leeds, Jason Allen-Paisant spent his early childhood living with his grandmother in Coffee Grove, a hilly rural district of Jamaica which was cut off from basic amenities such as electricity and water. Seen through the eyes of a child, Coffee Grove was, he notes, “both a tiny place and a huge planet”. There he developed a close relationship with the local plant life through climbing trees, picking fruit and helping his grandmother harvest yams on the “grung”, the local name for their small plot of land.</p><p>Allen-Paisant later yearned for pastures new, moving first to Paris and then to Britain to study at Oxford. His dream of upward mobility had become a reality, yet in the UK he noticed his interactions with nature were few and far between. He came to realise “just how much class keeps people in Britain from the privileges of land and soil and also keeps them from the tenderness that comes with forming kinship with the earth”.</p> <a href="https://www.theguardian.com/books/2026/apr/16/the-possibility-of-tenderness-by-jason-allen-paisant-audiobook-review-meditations-on-nature-and-belonging">Continue reading...</a>', '2026-04-16T09:14:37-05:00', 816000);
