INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/science/2026/apr/16/red-hair-gene-favoured-natural-selection-study', 'Red hair gene favoured by natural selection over last 10,000 years, study finds', '2026-04-16T14:21:09+00:00', '<p>Scientists who analysed nearly 16,000 ancient remains suggest red hair and fair skin is favoured for vitamin D production</p><p>People with red hair who have put up with teasing or “fiery” stereotypes may be pleased to learn that they appear to be winners from an evolutionary perspective. A large genetics study has revealed that, in Europe, the gene for red hair has been actively selected for more than 10,000 years.</p><p>The study did not aim to uncover the reasons for the trend, but focused on the broader question of whether human evolution has plateaued since the advent of agriculture. By analysing DNA from nearly 16,000 ancient human remains and more than 6,000 living individuals, the scientists provided compelling evidence that, in fact, biological evolution has continued apace.</p> <a href="https://www.theguardian.com/science/2026/apr/16/red-hair-gene-favoured-natural-selection-study">Continue reading...</a>', '2026-04-16T09:28:23-05:00', 432000);
