INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/16/vermont-dairy-workers-immigration', '‘I don’t go out’: Vermont’s undocumented dairy workers live in fear after immigration raids', '2026-04-16T11:00:56+00:00', '<p>A tenfold increase in the number of immigration detentions has compelled many workers to barely leave the farms where they work</p><ul><li><p><a href="https://www.theguardian.com/environment/2026/apr/15/vermont-dairy-industry-migrant-labor-workers-rights">‘They want to keep denying us our rights’: workers in Vermont’s $5.4bn dairy industry fight for basic labor protections</a></p></li></ul><p>Last spring, José Edilberto Molina-Aguilar was resting in his bedroom when a co-worker burst through the front door. Out his window, Molina-Aguilar, a 37-year-old dairy worker from Chiapas, Mexico, caught sight of the olive green uniforms of immigration enforcement officials who later claimed they had pursued a worker on to the farm property.</p><p>A farm manager told Molina-Aguilar and five of his co-workers at Pleasant Valley Farms, <a href="https://www.theguardian.com/world/vermont">Vermont</a>’s largest dairy, in Berkshire, about three miles from the Canadian border, to come outside.</p> <a href="https://www.theguardian.com/environment/2026/apr/16/vermont-dairy-workers-immigration">Continue reading...</a>', '2026-04-16T12:24:58-05:00', 23040000);
