INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/nils-pratley-on-finance/2026/apr/16/it-will-take-more-than-600m-a-year-to-boost-uk-industrial-competitiveness', 'It will take more than £600m a year to boost UK industrial competitiveness | Nils Pratley', '2026-04-16T17:44:39+00:00', '<p>Bics fix accepts nose-bleed energy bills are a structural problem but pretends they are only an issue for a narrow section of industry</p><p>It is “bold action” to boost UK competitiveness, claimed the government. Not everybody shared that assessment of <a href="https://www.theguardian.com/business/2026/apr/15/rachel-reeves-energy-bill-support-business-iran-war">the British industrial competitiveness scheme (Bics)</a>, the long-awaited plan to cut electricity bills for UK manufacturers by up to 25% – or, at least, to cut them for a subset of firms that are aligned with the eight chosen sectors of the “modern” industrial strategy.</p><p>“Gas intensive industries in the UK have been shamefully ignored by the government in this announcement – it’s a total disgrace,” said Gary Smith, the general secretary of the GMB union, banging the drum for the likes of ceramics-makers and brickmakers that aren’t deemed modern enough for support. Employer bodies mostly did the polite thing of welcoming government assistance of any form before using phrases such as “drop in the ocean”.</p> <a href="https://www.theguardian.com/business/nils-pratley-on-finance/2026/apr/16/it-will-take-more-than-600m-a-year-to-boost-uk-industrial-competitiveness">Continue reading...</a>', '2026-04-16T12:54:14-05:00', 576000);
