INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/17/the-dogs-gaze-by-thomas-laqueur-review-the-art-of-the-canine-from-velazquez-to-picasso', 'The Dog’s Gaze by Thomas Laqueur review – the art of the canine, from Velázquez to Picasso', '2026-04-17T06:00:25+00:00', '<p>A clever and beautiful survey of dogs in painting, with a brilliant interpretation of their role at its heart</p><p>Thirty-five thousand years ago, in&nbsp;the Ardèche region of France, Paleolithic artists drew a spectacular bestiary on the walls of&nbsp;the Chauvet cave. Their focus was apex predators, so there were lots of&nbsp;lions, as well as mammoths and woolly rhinoceroses. Dogs were nowhere to be seen, and yet in the soft&nbsp;sediment on the limestone floor of&nbsp;the cave, there are traces of canid pawprints next to human footprints. Two fellow creatures, most likely a&nbsp;boy&nbsp;and a dog, stood together, about&nbsp;10,000 years after the art was&nbsp;made, looking up at the walls in wonder. Here&nbsp;was a moment of shared contemplation, followed perhaps by a&nbsp;glance to see the other’s reaction.</p><p>In this luminous book, the American cultural historian Thomas Laqueur explores what he calls “the dog’s gaze”. The dog was the first animal to live companionably with humans, and Laqueur argues that this marks the boundary between nature and culture. It is this threshold status that has, in turn, qualified the dog to play a rich, symbolic part in western art. Just having dogs in a picture – snuffling for picnic crumbs in Seurat’s <a href="https://www.artic.edu/artworks/27992/a-sunday-on-la-grande-jatte-1884">La Grande Jatte</a> or trooping home in Bruegel the Elder’s <a href="https://www.khm.at/en/artworks/hunters-in-the-snow-winter-327-1">Hunters in the Snow</a> – becomes a way for an artist to pack an image with extra resonance and second-order meaning.</p> <a href="https://www.theguardian.com/books/2026/apr/17/the-dogs-gaze-by-thomas-laqueur-review-the-art-of-the-canine-from-velazquez-to-picasso">Continue reading...</a>', '2026-04-17T01:05:05-05:00', 282000);
