INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/money/gallery/2026/apr/17/homes-for-sale-in-england-near-marathon-routes-in-pictures', 'Homes for sale in England near marathon routes – in pictures', '2026-04-17T06:00:25+00:00', '<p>From running through open countryside in historic beauty spots to pounding the streets of London</p> <a href="https://www.theguardian.com/money/gallery/2026/apr/17/homes-for-sale-in-england-near-marathon-routes-in-pictures">Continue reading...</a>', '2026-04-17T01:10:23-05:00', 600000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/17/microsoft-us-tech-firms-lobbied-eu-secrecy-rules-datacentre-emissions', 'US tech firms successfully lobbied EU to keep datacentre emissions secret', '2026-04-17T06:00:24+00:00', '<p>Legally questionable confidentiality clause adopted almost word for word from demands of Microsoft and trade groups</p><p>Microsoft and other US tech companies successfully lobbied the EU to hide the environmental toll of their datacentres, an investigation has found, with demands to block a database of green metrics from public view written almost word for word into EU rules.</p><p>The secrecy provision, which the European Commission added to its proposal almost verbatim after industry lobbying in 2024, hinders scrutiny of the pollution that individual datacentres emit. It leaves researchers with just national-level summaries of their energy footprints.</p> <a href="https://www.theguardian.com/technology/2026/apr/17/microsoft-us-tech-firms-lobbied-eu-secrecy-rules-datacentre-emissions">Continue reading...</a>', '2026-04-17T01:10:23-05:00', 600000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/17/more-than-15m-oysters-to-be-released-in-the-north-sea-for-uk-rewilding-project', 'More than 15m oysters to be released in the North Sea for UK rewilding project', '2026-04-17T06:00:23+00:00', '<p>Exclusive: Experts say scheme will help repair damaged marine ecosystems while sequestering large amounts of carbon</p><p>More than 15m juvenile oysters are to be released into the North Sea in one of the biggest rewilding projects in UK waters.</p><p>The scheme, which will use a unique rearing process, hopes to re-establish a huge oyster bed around Orkney that experts say will create a “trophic cascade” of climate and ecological benefits.</p> <a href="https://www.theguardian.com/environment/2026/apr/17/more-than-15m-oysters-to-be-released-in-the-north-sea-for-uk-rewilding-project">Continue reading...</a>', '2026-04-17T01:10:23-05:00', 600000);
