INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/17/george-robertson-cutting-welfare-to-fund-defence', 'A question for those desperate to cut benefits to fund defence: who exactly are you willing to impoverish? | Polly Toynbee', '2026-04-17T07:00:24+00:00', '<p>George Robertson has joined Reform and the Tories in making the case. Look  welfare recipients in the face and say that</p><p>The benefits budget is now a magic money tree. Whenever Conservatives or Faragists make wild promises – tax cuts, more police, more punishment, more bonuses for marriage – and are asked how they would pay, the answer is always “welfare”. The sums are enormous. “Only the Conservatives will <a href="https://www.conservatives.com/news/how-can-we-reform-the-welfare-budget#:~:text=Rachel%20Reeves%20hiked%20taxes%20by%20%C2%A326%20billion,will%20cut%20welfare%20spending%20by%20%C2%A323%20b">cut welfare spending by £23bn</a> and get Britain working again,” the party insists.</p><p>More unexpected was the klaxon from the Labour peer George Robertson this week, demanding a cut in benefits to finance defence. “We cannot defend Britain with an ever-expanding welfare budget,” <a href="https://www.bbc.co.uk/news/articles/cje4n5ppgw7o">said the ex-Nato chief</a>, wanting to pluck this juicy plum to fund defence. Good to see him slapped down sharply by the government: there is no “zero-sum game” between these two budgets, <a href="https://www.theguardian.com/politics/2026/apr/15/welfare-defence-spending-treasury-minister-james-murray">said the chancellor’s deputy, James Murray</a>.</p><p><strong>Guardian Newsroom: Can Labour come back from the brink?<br></strong>On Thursday 30 April, join Gaby Hinsliff, Zoe Williams, Polly Toynbee and Rafael Behr as they discuss how much of a threat Labour faces from the Green party and Reform UK – and whether Keir Starmer can survive as leader. Book tickets <em><a href="https://www.theguardian.com/guardian-live-events/2026/feb/03/guardian-newsroom-can-labour-come-back-from-the-brink">here</a> or at <a href="https://www.theguardian.com/guardian-live-events/2026/feb/03/guardian-newsroom-can-labour-come-back-from-the-brink">guardian.live</a></em></p><p>Polly Toynbee is a Guardian columnist</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/17/george-robertson-cutting-welfare-to-fund-defence">Continue reading...</a>', '2026-04-17T02:12:09-05:00', 708000);
