INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/17/finance-leaders-warn-over-claude-mythos-as-uk-banks-prepare-to-use-powerful-anthropic-ai-tool', 'Finance leaders warn over Mythos as UK banks prepare to use powerful Anthropic AI tool', '2026-04-17T07:31:37+00:00', '<p>Release of new Claude model, so far limited to US firms, will expand to British institutions in coming days</p><p>British banks will be given access in the next week to a powerful AI tool that was deemed too dangerous to be released to the public, as a series of senior finance figures warned over its impact.</p><p>Anthropic, which has so far <a href="https://www.theguardian.com/technology/2026/apr/08/anthropic-ai-cybersecurity-software">limited the release</a> of the new model to a small clutch of primarily US businesses, including Amazon, Apple and Microsoft, said it would expand that to UK financial institutions.</p> <a href="https://www.theguardian.com/technology/2026/apr/17/finance-leaders-warn-over-claude-mythos-as-uk-banks-prepare-to-use-powerful-anthropic-ai-tool">Continue reading...</a>', '2026-04-17T02:41:14-05:00', 576000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/games/2026/apr/17/replaced-review-cyberpunk-tribute-pc-xbox', 'Replaced review – nostalgic cyberpunk tribute has few ideas of its own', '2026-04-17T07:30:24+00:00', '<p><strong>PC, Xbox; Sad Cat Studios<br></strong>This pulpy sci-fi thriller is a beautiful, if deferential, homage to the genre greats, with a poignant real-world echo</p><p>For all of cyberpunk’s cautionary tales of shady corporations and transhumanist folly, it is the genre’s arresting imagery that looms largest in the pop culture imagination. Petroleum flares light up the perpetually rainy Los Angeles of Blade Runner; in the novel <a href="https://www.theguardian.com/books/2014/jul/28/william-gibson-neuromancer-cyberpunk-books">Neuromancer</a>, the sky is the “colour of television, tuned to a dead channel”.</p><p>Replaced, a new 2D action-platformer from Belarus-based outfit Sad Cat Studios, leans into the steel and sprawl that the genre is famed for. The game also offers a wrinkle to cyberpunk’s longstanding, somewhat overfamiliar visual palette: it floods the screen with softly diffusing sepia and warm primary colours, particularly in the densely populated residential areas you’re able to explore. The mood is comforting rather than ominous, cosy rather than clinical, as if this dystopian sci-fi has been touched by an unlikely hand – that of cottagecore godfather Thomas Kinkade.</p><p>Replaced is out now; £16.99/$19.99</p> <a href="https://www.theguardian.com/games/2026/apr/17/replaced-review-cyberpunk-tribute-pc-xbox">Continue reading...</a>', '2026-04-17T02:42:18-05:00', 714000);
