INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/17/weather-tracker-hail-covers-parts-of-tunisia-and-algeria-like-snow', 'Weather tracker: hail covers parts of Tunisia and Algeria like snow', '2026-04-17T07:49:39+00:00', '<p>Accumulations of up to 3cm deep reported as severe thunderstorms also bring heavy downpours to central Italy</p><p>Severe thunderstorms have affected the Mediterranean this week. On Monday, a surface low-pressure system in the Mediterranean in conjunction with an upper air cut-off low, led to thunderstorms over north Africa. Their intensity was aided by the hot precursor conditions.</p><p>Algeria and Tunisia were notably affected by the thunderstorms, with some hail accumulation layers as a result. When so much hail forms, it starts to lay down sheets of hail, covering the ground like snow. Hail accumulations of up to 3cm were reported in Oum Ladjoul and Hammam Sokhna in Algeria, and there were hailstones of up to 3cm in diameter in Makthar, Tunisia. Thunderstorms continued in the region through the following day, with further hail accumulations, notably in Ouled Bousmir, Tunisia, where there was a layer about 2cm deep.</p> <a href="https://www.theguardian.com/environment/2026/apr/17/weather-tracker-hail-covers-parts-of-tunisia-and-algeria-like-snow">Continue reading...</a>', '2026-04-17T02:56:59-05:00', 438000);
