INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/17/colombia-convenes-climate-coalition-of-the-willing-to-break-global-fossil-fuel-deadlock', 'Colombia convenes climate ‘coalition of the willing’ to break global fossil fuel deadlock', '2026-04-17T08:00:24+00:00', '<p>Santa Marta conference born out of frustration at Cop summits, where renewable progress has been stalled by major polluters</p><p>Everybody knows fossil fuels cause climate breakdown, but until recently, mention of them was all but erased from the annual UN climate summits. Last year, two weeks of discussions ended without fossil fuels being mentioned in the final outcome.</p><p>Frustration with those talks led a small developing country with a large fossil fuel sector – Colombia, the largest coal and fourth biggest oil exporter in the Americas – to rewrite the rules. With co-convener the Netherlands, and support from more than 50 countries, Colombia will host a groundbreaking new global conference this month to begin the long-awaited “transition away from fossil fuels”.</p> <a href="https://www.theguardian.com/environment/2026/apr/17/colombia-convenes-climate-coalition-of-the-willing-to-break-global-fossil-fuel-deadlock">Continue reading...</a>', '2026-04-17T03:05:16-05:00', 294000);
