INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/17/the-best-recent-and-thrillers-review-roundup', 'The best recent crime and thrillers – review roundup', '2026-04-17T11:00:43+00:00', '<p>The Keeper by Tana French; The Kindness of Strangers by Emma Garman; Mrs Shim Is a Killer by Kang Jiyoung; A Killer in the Family by Amin Ahmad; The Drowning Place by Sarah Hilary</p><p><strong><a href="https://guardianbookshop.com/the-keeper-9780241823767/">The Keeper</a> by Tana French</strong><strong> (Viking, £16.99)</strong><br>', '2026-04-17T06:11:23-05:00', 642000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/17/uk-onlyfans-3bn-valuation-sell-stake-us-architect-capital-leonid-radvinsky', 'UK’s OnlyFans tops $3bn valuation amid talks to sell stake to US investor', '2026-04-17T11:02:40+00:00', '<p>Adult video platform to sell minority stake to increase stability after death of its owner Leonid Radvinsky</p><ul><li><p><a href="https://www.theguardian.com/business/live/2026/apr/17/wheat-price-jump-iran-war-fertiliser-food-insecurity-oil-stock-markets-latest-updates">Business live – latest updates</a></p></li></ul><p>OnlyFans, <a href="https://www.theguardian.com/news/ng-interactive/2026/mar/29/onlyfans-owners-leonid-radvinsky-death-porn-money-making-machine">the UK adult video platform</a>, is in talks to sell a minority stake to a US investor that will value the business at more than $3bn (£2.2bn).</p><p>The London-based company is in advanced talks to sell a stake of less than 20% to the San Francisco-based investment firm Architect Capital, according to the <a href="https://www.ft.com/content/e06cdb42-6967-4e7c-b6d5-9516883c73bc?syn-25a6b1a6=1">Financial Times</a>. Sources familiar with the process confirmed the talks to the Guardian.</p> <a href="https://www.theguardian.com/technology/2026/apr/17/uk-onlyfans-3bn-valuation-sell-stake-us-architect-capital-leonid-radvinsky">Continue reading...</a>', '2026-04-17T06:11:23-05:00', 522000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'synthetic:6815672747442fa1bf3fab9692b8d12ec1c77895', 'Police investigate security incident near Israeli embassy in London', '2026-04-17T11:11:25+00:00', NULL, '2026-04-17T06:17:49-05:00', 384000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/books/2026/apr/14/my-year-in-paris-with-gertrude-stein-by-deborah-levy-review-wonderfully-entertaining', 'My Year in Paris With Gertrude Stein by Deborah Levy review – wonderfully entertaining', '2026-04-14T06:01:02+00:00', '<p>Biography mingles with fiction as Levy explores the avant-garde writer through the story of three female friends in Paris</p><p>The narrator of Deborah Levy’s witty scherzo of a “fiction” – “novel” isn’t the word for this uncategorisable book – thinks that Gertrude Stein would have liked Sigmund Freud. She imagines them enjoying a cigar together while their wives make small talk. Would Frau Freud “have exchanged her recipe for boiled beef with Alice B [Toklas]’s recipe for hashish fudge”? The two never met (though with her interest in the “bottom character” and his in the “unconscious”, Stein and Freud would have had plenty to talk about), but that barely matters. This book is full of things that don’t actually happen, of relationships that are not what the people involved suppose them to be, of digressions and fantasies and encounters that are imagined but never take place.</p><p>It all starts with a lost cat. The cat is called “it”: lower-case “i” followed by lower-case “t”. This causes all sorts of linguistic confusion, highlighting the way we use the word “it” to mean something indeterminate (as in the first sentence of this paragraph), or something trivial, or something tremendous. The phrase “lost it” recurs, the “it” meaning – variously – one’s mind, sympathy with Ernest Hemingway, daring to be as unconventional as Gertrude Stein, the stream of consciousness “flowing under the mowed and manicured golf courses on which men swung their clubs in the 21st century”, the temptation to smile while being undermined by a patronising man, the drudgery of housekeeping, the thing – which might be obedience or shame – that holds an artist back from becoming a modernist … or love, or one’s mother, or a black-and-white cat with one deformed ear.</p> <a href="https://www.theguardian.com/books/2026/apr/14/my-year-in-paris-with-gertrude-stein-by-deborah-levy-review-wonderfully-entertaining">Continue reading...</a>', '2026-04-17T06:18:53-05:00', 277200000);
