INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/17/south-korea-escaped-wolf-captured-returned-zoo-safely', 'South Koreans breathe sighs of relief as escaped wolf is returned to zoo safely', '2026-04-17T11:49:38+00:00', '<p>Nine-day search for two-year-old Neukgu gripped nation and sparked safety concerns for animal and public</p><p>The internet in South Korea erupted in celebration as a two-year-old wolf that escaped from a zoo was captured safely after a nine-day search that had gripped the nation and made the animal a national celebrity.</p><p>The male wolf, named Neukgu, burrowed out of his enclosure at the O-World zoo in Daejeon on 8 April. Animal rights activists questioned whether the wolf could survive outside the zoo and also worried he might be killed during capture, something that happened to a puma that escaped from the same zoo in 2018.</p> <a href="https://www.theguardian.com/world/2026/apr/17/south-korea-escaped-wolf-captured-returned-zoo-safely">Continue reading...</a>', '2026-04-17T06:56:50-05:00', 432000);
