INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('wsj', 'General', 'WP-WSJ-0003506176', 'U.K.&#x2019;s Starmer Under Fresh Scrutiny Over Epstein Fallout', '2026-04-17T11:58:00+00:00', 'The prime minister denies knowing that disgraced former U.S. envoy Peter Mandelson&#x2014;a friend of Epstein&#x2014;hadn&#x2019;t been cleared by security vetting.', '2026-04-17T07:01:21-05:00', 204000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/17/coral-reefs-extinction-global-warming-jason-momoa', 'Coral reefs are nearing extinction. 2026 must mark a turning point | Jason Momoa', '2026-04-17T12:00:44+00:00', '<p>At 1.5C of global warming, up to 90% of coral reefs could be lost. The next few months could be a defining moment</p><p>Where I come from – Hawai’i – the reef isn’t just something you look at. It’s part of us. It feeds our families, protects our shores, and lives at the center of our culture. In our stories, coral is one of our oldest ancestors. It’s a reminder that everything in the ocean, and all of us, are connected.</p><p>Right now, that integral connection is under threat.</p><p>Jason Momoa is an actor, film-maker, and UNEP Advocate for Life Below Water, dedicated to protecting our oceans and advancing global awareness around coral reef conservation</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/17/coral-reefs-extinction-global-warming-jason-momoa">Continue reading...</a>', '2026-04-17T07:04:08-05:00', 204000);
