INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/17/new-uk-electric-car-price-petrol-ev-autotrader', 'Average new UK electric car price is now lower than petrol vehicles', '2026-04-17T12:35:28+00:00', '<p>Autotrader says average EV cost is £785 cheaper, in an important milestone in the move away from fossil fuels</p><p>The price of new battery electric cars has fallen below petrol cars in the UK for the first time, according to the car sales website Autotrader, in a significant milestone in Britain’s transition away from fossil fuels.</p><p>The average price of a new electric car listed on the website was £42,620, compared with £43,405 for a new petrol model – making the former £785 cheaper based on advertised prices after discounts.</p> <a href="https://www.theguardian.com/environment/2026/apr/17/new-uk-electric-car-price-petrol-ev-autotrader">Continue reading...</a>', '2026-04-17T07:45:28-05:00', 600000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/17/pope-leo-jd-vance-donald-trump-catholicism', 'Is the pope Catholic? JD Vance thinks he has an answer | Marina Hyde', '2026-04-17T12:44:03+00:00', '<p>When it comes to theology, Donald Trump’s vice-president clearly knows best. Are we about to see an American break with Rome?</p><p>The battle to be the absolute worst Trump henchman can feel so closely fought. But in the end, it’s always JD Vance, isn’t it? You would say Stephen Miller, but Miller’s too hidden to qualify as a front-of-house henchman among the US president’s court of grotesques. Stephen’s clearly been judged so wantonly horrifying that the administration must keep him out of public view. If you enter the store, Miller is the only-for-the-initiated entity alluded to in a whisper by the oleaginous sales assistant. “We do have something in the back – off-the-books, as it were – if sir is after something a little more … <em>specialist</em>.”</p><p>But Vance? Vance besets us like the 11th plague – the plague of media appearances. For the next South Park season, I hope the creators give their brilliantly ghastly little vice-president avatar a papal mitre to wear. After all, here we have a man whose pick-me book on his journey to Catholicism has yet to even be published. That tome currently lies in the rectum of HarperCollins, ready to be excreted in June – yet inevitably, Vance is already giving menacing doctrinal advice to the pope as part of the multi-theatre fallout of Operation Epic Facepalm.</p><p>Marina Hyde is a Guardian columnist</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/17/pope-leo-jd-vance-donald-trump-catholicism">Continue reading...</a>', '2026-04-17T07:52:52-05:00', 528000);
