INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/australia-news/2026/apr/18/jacinta-allan-wants-voters-to-see-victorias-12-year-old-labor-government-as-new-and-united-can-she-cling-to-power', 'Jacinta Allan wants voters to see Victoria’s 12-year-old Labor government as ‘new and united’. Can she cling to power?', '2026-04-17T15:00:49+00:00', '<p>With a reshuffled cabinet, the premier is hoping to quell leadership rumblings as her party seeks an unprecedented fourth term</p><ul><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>As the Victorian premier, Jacinta Allan, stood alongside the fresh faces in her reshuffled cabinet on Wednesday, she attempted to send her increasingly jaded electorate a blunt message: despite its 12 years in power, her government is – apparently – new.</p><p>In her opening four-minute preamble to reporters, Allan - whose Labor government will in November seek an unprecedented fourth term - repeated the word 17 times. In one sentence alone, she referred to her “new cabinet”, “new portfolios”, “new solutions” and “new areas that are going to drive this government forward”.</p><p><em>Benita Kolovos is Guardian Australia’s Victorian state correspondent</em></p> <a href="https://www.theguardian.com/australia-news/2026/apr/18/jacinta-allan-wants-voters-to-see-victorias-12-year-old-labor-government-as-new-and-united-can-she-cling-to-power">Continue reading...</a>', '2026-04-17T10:12:12-05:00', 684000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/australia-news/2026/apr/18/nsw-should-think-twice-before-banning-globalise-the-intifada-after-court-struck-down-anti-protest-law-legal-expert-says-ntwnfb', 'NSW should think twice before banning ‘globalise the intifada’ after court struck down anti-protest law, legal expert says', '2026-04-17T15:00:49+00:00', '<p>Another lawyer says ruling ‘puts brakes on the Minns government’s ability to use executive power to minimise people’s rights to protest’</p><ul><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>The Minns government should think twice before imposing an outright ban on <a href="https://www.theguardian.com/australia-news/2025/dec/23/globalise-the-intifada-meaning-translation-palestinian-protest-chant-ban-nsw">the phrase “globalise the intifada”</a> in the wake of a landmark finding that could limit attempts to control speech and protests, a leading constitutional expert has said.</p><p>New South Wales’ highest court ruled in favour of the Palestine Action Group and Blak Caucus on Thursday, striking down an anti-protest law introduced after the <a href="https://www.theguardian.com/australia-news/bondi-beach-shooting-sydney-australia">Bondi beach terror attack</a> that gave police the power to restrict marches, including the <a href="https://www.theguardian.com/australia-news/2026/feb/14/inside-the-chaos-at-sydney-anti-herzog-protest-ntwnfb">anti-Herzog rally in February</a>.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/18/nsw-should-think-twice-before-banning-globalise-the-intifada-after-court-struck-down-anti-protest-law-legal-expert-says