INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/17/cia-john-brennan-russia-trump-investigation', 'Lead prosecutor on investigation into former CIA director no longer on case', '2026-04-17T21:01:41+00:00', '<p>Maria Medetis Long had expressed doubts over case of John Brennan, whose agency said Russia boosted Trump in 2016</p><ul><li><p><a href="https://www.theguardian.com/news/2026/feb/17/sign-up-for-the-breaking-news-us-email-to-get-newsletter-alerts-direct-to-your-inbox?utm_medium=ACQUISITIONS_STANDFIRST&amp;utm_campaign=BN22326&amp;utm_content=signup&amp;utm_term=standfirst&amp;utm_source=GUARDIAN_WEB">Sign up for the Breaking News US email to get newsletter alerts in your inbox</a></p></li></ul><p>A federal prosecutor leading the investigation into former CIA director John Brennan is no longer working on the case after expressing reservations about it, according to a person familiar with the matter.</p><p>The prosecutor, Maria Medetis Long, informed attorneys involved in the case she was no longer handling it, <a href="https://edition.cnn.com/2026/04/17/politics/prosecutor-running-john-brennan-investigation-removed">according to CNN</a>, which first reported she was leaving the case. Medetis Long is a career attorney serving as the chief of the national security division in the US attorney’s office for the southern district of Florida. The Department of Justice did not immediately respond to a request for comment.</p> <a href="https://www.theguardian.com/us-news/2026/apr/17/cia-john-brennan-russia-trump-investigation">Continue reading...</a>', '2026-04-17T16:09:04-05:00', 444000);
