INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/video/2026/apr/18/scientists-dig-broad-shelled-turtles-stuck-under-mud-in-dried-up-wetlands-video', 'Scientists dig broad-shelled turtles stuck under mud in dried up wetlands – video', '2026-04-17T15:00:48+00:00', '<p>Footage supplied by the office of the Greens legislative council member Cate Faehrmann shows scientists digging to reach broad-shelled turtles stuck under boggy mud in the Gingham watercourse.&nbsp;Researchers from the University of New England have been desperately trying to help more than 300 turtles they say have been left to die in the Gwydir wetlands after the NSW state water agency stopped environmental flows after a landowner complained about overflow on their property. UNE conservation biologist Prof Debbie Bower called the scene a ''disaster''. ''These deaths are incomprehensible, given there is environmental water sitting in the dam. This could save the turtles, but WaterNSW is just not allowing its release,'' she says </p> <a href="https://www.theguardian.com/environment/video/2026/apr/18/scientists-dig-broad-shelled-turtles-stuck-under-mud-in-dried-up-wetlands-video">Continue reading...</a>', '2026-04-17T23:37:26-05:00', 48960000);
