INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/18/gina-rinehart-australian-mining-billionaire-court-ruling-rival-family-ntwnfb', 'Iron will: Australia’s richest person counts the cost as court orders she share mining millions with rival family', '2026-04-18T02:00:00+00:00', '<p>Gina Rinehart, who’s been called Australia’s ‘female Donald Trump’, has long fought claims from the family of her father’s business partner – as well as her own children</p><ul><li><p>Full Story podcast: <a href="https://www.theguardian.com/australia-news/audio/2026/apr/16/how-gina-rinehart-lost-hundreds-of-millions-of-dollars-in-court-full-story-podcast">How Gina Rinehart lost hundreds of millions of dollars in court</a></p></li></ul><p>Australia’s richest person is reeling after a landmark court decision found her company must pay royalties worth hundreds of millions of dollars to a rival mining dynasty.</p><p>Gina Rinehart, a multibillionaire with political connections in both the White House and the Australian parliament, has been described by members of the US conservative movement as <a href="https://www.theguardian.com/australia-news/2025/mar/31/a-female-donald-trump-how-gina-rinehart-is-pushing-trumps-message-australia-ntwnfb">“a female Donald Trump”</a>. The 72-year-old, who inherited her father’s iron ore empire in Australia’s Pilbara region, has fought multiple claims against the family company Hancock Prospecting that were first launched in 2010.</p> <a href="https://www.theguardian.com/business/2026/apr/18/gina-rinehart-australian-mining-billionaire-court-ruling-rival-family-ntwnfb">Continue reading...</a>', '2026-04-18T00:45:39-05:00', 13500000);
