INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/18/fossil-fuel-trump-green-revolution-us-iran-renewable-energy', 'Who’d have thought a fossil-fuel shill like Trump would be the one to spark a green revolution? | George Monbiot', '2026-04-18T07:00:07+00:00', '<p>The US attack on Iran has made the need for renewable energy inarguable. Environmentalists are now being seen for the pragmatists that they are</p><p>Donald Trump has done more to accelerate the energy transition than anyone else alive. Fossil fuel <a href="https://www.nytimes.com/2024/11/01/climate/oil-gas-donations-trump.html">companies bankrolled his presidential campaign</a> to stop the transition in its tracks. But when you back a volatile narcissist, unable to concentrate for more than a few minutes at a time, you shouldn’t expect to control the outcome.</p><p>It’s not that the fossils are suffering yet. As prices have soared since Trump and Netanyahu attacked Iran, oil executives have been selling shares at gobsmacking prices: the CEO of Chevron, for example, <a href="https://heated.world/p/chevrons-ceo-made-104-million-while">has cashed $104m so far this year.</a> Vladimir Putin has <a href="https://www.theguardian.com/world/2026/mar/04/middle-east-conflict-offers-economic-lifeline-to-russias-flagging-war-machine">also received a massive boost</a> to his Ukraine invasion budget. <a href="https://www.brennancenter.org/our-work/analysis-opinion/fossil-fuel-industry-donors-see-major-returns-trumps-policies">As promised</a>, Trump has gutted <a href="https://www.theguardian.com/environment/2026/feb/14/trump-obama-climate-rule-takeaways">clean energy rules</a> and <a href="https://www.oneearthnow.org/p/trump-and-republicans-want-to-block">programmes</a>, <a href="https://www.eenews.net/articles/interior-totalenergies-strike-deal-ending-us-offshore-wind-projects/">green alternatives</a> and environmental science. A fortnight ago, <a href="https://www.bloomberg.com/opinion/articles/2026-03-31/trump-s-iran-war-is-accelerating-the-global-energy-transition">he stated</a>, with the usual quantum of evidence (zero): “The environmentalists, I mean, they are terrorists … I call them environmental terrorists.”</p><p>George Monbiot is a Guardian columnist</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/18/fossil-fuel-trump-green-revolution-us-iran-renewable-energy">Continue reading...</a>', '2026-04-18T02:02:53-05:00', 168000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/18/country-diary-return-of-the-manx-shearwaters-this-island-is-their-home', 'Country diary: Return of the Manx shearwaters – this island is their home | Tim Earl', '2026-04-18T04:30:03+00:00', '<p><strong>Langness, Isle of Man:</strong> With their epic migrations, they are special birds, but especially so here, the place that coined the name</p><p>A swallow recorded at the start of March, sand martins mid-month. This year, many <a href="https://www.theguardian.com/environment/2026/apr/04/birds-butterflies-britain-shows-signs-of-earliest-spring-on-record">harbingers of spring have come early</a> due to the warming climate, so here on the island, the question was: would our Manx shearwaters return early too?</p><p>Few places have birds named after them, but the Isle of Man is one (Sardinia another, for Sardinian warblers), the name granted in 1835 thanks to a large shearwater colony on the Calf of Man, an island off our south-west corner. That population was devastated by rats from a shipwreck, but after a rodent eradication programme by the Manx Wildlife Trust, numbers have rebounded to more than 1,500 breeding pairs.</p> <a href="https://www.theguardian.com/environment/2026/apr/18/country-diary-return-of-the-manx-shearwaters-this-island-is-their-home">Continue reading...</a>', '2026-04-18T02:02:53-05:00', 9120000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/18/stranded-dying-german-whale-troubled-relationship-sea-timmy', 'Stranded and dying, the German whale is a parable of our troubled relationship with these sea giants', '2026-04-18T06:00:05+00:00', '<p>Even as we empathise with these intelligent animals, our relentless push for resources kills them in their thousands, just as whalers once hunted them to the brink of extinction</p><p>For weeks now, a humpback whale has been trying to die. Entangled in ropes, it had <a href="https://www.theguardian.com/world/2026/mar/29/hope-running-low-for-humpback-whale-stranded-off-german-coast">wandered into the shallow Baltic Sea</a>. Unable to feed, it is now subject to extreme dehydration, since whales satisfy their thirst through the fish they eat.</p><p>In such a parlous situation, the whale’s last resort was to strand itself on Poel Island, in the Bay of Wismar. Sadly, it has been a slow death. Beached whales die because they are crushed by their own weight. The German humpback’s agony may have been prolonged because it lay in shallow water and was thus only partly submerged.</p> <a href="https://www.theguardian.com/environment/2026/apr/18/stranded-dying-german-whale-troubled-relationship-sea-timmy">Continue reading...</a>', '2026-04-18T02:02:53-05:00', 3720000);
