INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/games/2026/apr/18/super-mario-nintendo-luigi-inspiration', 'Father of man who inspired Super Mario was also named Luigi, researcher finds', '2026-04-18T07:00:07+00:00', '<p>Elisabeth Zetland, a senior researcher at MyHeritage, found that the actual Luigi had immigrated to US from Italy</p><p>Gaming enthusiasts have known for years that Nintendo named <a href="https://www.theguardian.com/games/super-mario">its mustachioed, superhero plumber</a> after the company’s landlord, Washington state businessman Mario Arnold Segale.</p><p>But it has only just been determined that Nintendo may have unknowingly named Super Mario’s fictional brother after Segale’s real-life father: Luigi, whose biography evokes that of millions of 20th-century US immigrants from Italy.</p> <a href="https://www.theguardian.com/games/2026/apr/18/super-mario-nintendo-luigi-inspiration">Continue reading...</a>', '2026-04-18T02:07:03-05:00', 420000);
