INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/travel/2026/apr/18/europe-summer-holiday-flight-cross-channel-travel-cancelled-flights-airport-eu-ees', 'Can Europe avoid a summer of holiday flight and cross-Channel travel chaos?', '2026-04-18T07:00:07+00:00', '<p>Passengers face risk of cancellations due to fuel shortages – and long airport queues due to EU entry-exit system</p><ul><li><p><a href="https://www.theguardian.com/travel/2026/apr/18/what-to-do-if-flights-cancelled-holidays-disrupted-iran-war-eu-ees">What are your rights if your holiday flight is cancelled?</a></p></li></ul><p>Holidaymakers have faced numerous stresses in recent years when planning and budgeting for the sacred summer holiday. Holiday flights to Europe have kept growing despite a pandemic, a cost of living crisis and long airport queues, but summer 2026 threatens to bring fresh anxieties.</p><p>Legacies of Brexit mean longer border checks for Britons and most non-EU nationals to get into much of Europe, and the US-Israel war on Iran has prompted fears that airlines may not have enough fuel for every scheduled flight.</p> <a href="https://www.theguardian.com/travel/2026/apr/18/europe-summer-holiday-flight-cross-channel-travel-cancelled-flights-airport-eu-ees">Continue reading...</a>', '2026-04-18T02:12:17-05:00', 732000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/travel/2026/apr/18/what-to-do-if-flights-cancelled-holidays-disrupted-iran-war-eu-ees', 'What are my rights if flights are cancelled and holidays disrupted due to fuel shortage?', '2026-04-18T07:00:07+00:00', '<p>Iran war and EU’s new entry-exit system could lead to travel misery this summer, but there are ways to mitigate it</p><ul><li><p><a href="https://www.theguardian.com/travel/2026/apr/18/europe-summer-holiday-flight-cross-channel-travel-cancelled-flights-airport-eu-ees">Can Europe avoid a summer of travel chaos?</a></p></li></ul><p>The war in the Middle East has prompted fears that potential shortages of jet fuel could result in flight cancellations this summer and warnings that holidays could be severely disrupted.</p><p>Airports have said <a href="https://www.theguardian.com/world/2026/apr/10/european-airports-jet-fuel-shortages-flights-iran">jet fuel could run short within three weeks</a> as a result of supply problems after the strait of Hormuz was effectively closed when war broke out at the end of February.</p> <a href="https://www.theguardian.com/travel/2026/apr/18/what-to-do-if-flights-cancelled-holidays-disrupted-iran-war-eu-ees">Continue reading...</a>', '2026-04-18T02:12:17-05:00', 732000);
