INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/venezuelas-machado-to-hold-madrid-rally-as-opposition-frozen-out-after-maduro-capture', 'Venezuela’s Machado to hold Madrid rally as opposition frozen out after Maduro capture', '2026-04-18T08:00:08+00:00', '<p>Exiled leader to revive push for change amid US backing of Delcy Rodríguez and delays to democratic transition</p><p>Venezuela’s opposition leader, María Corina Machado, will seek to revive her push for political change with a rally in Madrid on Saturday, having found herself <a href="https://www.theguardian.com/world/2026/jan/06/venezuela-opposition-maria-corina-machado-setback-trump">sidelined by Donald Trump</a> after the abduction of the president Nicolás Maduro.</p><p>“Venezuela will be free,” the Nobel peace prize winner insisted in an interview on the eve of this weekend’s demonstration in the Puerta del Sol square, which is expected to draw tens of thousands of protesters.</p> <a href="https://www.theguardian.com/world/2026/apr/18/venezuelas-machado-to-hold-madrid-rally-as-opposition-frozen-out-after-maduro-capture">Continue reading...</a>', '2026-04-18T03:11:51-05:00', 702000);
