INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/politics/2026/apr/18/twilight-zone-iran-war-casts-deep-shadows-rachel-reeves-imf-gathering-washington', '‘It’s a twilight zone’: Iran war casts deep shadows over IMF gathering in Washington', '2026-04-18T04:00:03+00:00', '<p>Rachel Reeves joins global finance chiefs in highlighting how households and businesses are feeling the pain of higher energy prices</p><ul><li><p><a href="https://www.theguardian.com/world/live/2026/apr/18/middle-east-crisis-live-iran-warns-it-will-close-strait-of-hormuz-if-us-blockade-continues">Middle East crisis live: latest news updates</a></p></li></ul><p>The most severe energy shock since the 1970s, the risk of a global recession and households everywhere stomaching a renewed surge in the cost of living – hitting the most vulnerable hardest.</p><p>In a sweltering hot Washington DC this week, the message at <a href="https://www.theguardian.com/business/imf">the International Monetary Fund meetings</a> was chilling: things had been looking up for living standards around the world. But then came the Iran war.</p> <a href="https://www.theguardian.com/politics/2026/apr/18/twilight-zone-iran-war-casts-deep-shadows-rachel-reeves-imf-gathering-washington">Continue reading...</a>', '2026-04-18T03:28:25-05:00', 16080000);
