INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/17/the-guardian-view-on-a-much-needed-boost-for-the-arts-rebuilding-englands-cultural-landscape', 'The Guardian view on a much-needed boost for the arts: rebuilding England’s cultural landscape', '2026-04-17T17:13:51+00:00', '<p>Dazzling new additions like V&amp;A East are a source of national pride, but so are  much-loved regional institutions</p><p>The <a href="https://www.vam.ac.uk/east/museum/visit?srsltid=AfmBOopx2ciafZZelO9PW5n9AkjvkLDsGP4opqz9lPQP7eoTkw6n9HFH">V&amp;A East Museum</a>, which opens its doors for the first time in Stratford, London, on Saturday, is the latest addition to the buzzing East Bank cultural quarter on the Queen Elizabeth Olympic Park. This <a href="https://www.museumsassociation.org/museums-journal/news/2026/04/how-do-we-build-a-relationship-with-the-skeptical-generation-va-east-opens-its-doors/">£135m architect-designed V&amp;A outpost</a> is a short walk from the <a href="https://www.vam.ac.uk/east/storehouse/visit?srsltid=AfmBOope0ZreMXHTZpvcq4loleSqv2VC_yIgSHPqTxBfEIcNgSJeZNTL">V&amp;A East Storehouse</a> (on Time Magazine’s list of <a href="https://time.com/collection/worlds-greatest-places/2026/">The World’s Greatest Places to Visit 2026</a>) and Sadler’s Wells East, both of which arrived last year. <a href="https://www.theguardian.com/artanddesign/2024/feb/19/shades-of-grey-london-college-of-fashion-harry-potter">The London College of Fashion</a> has been there since 2024 and <a href="https://www.queenelizabetholympicpark.co.uk/east-bank/bbc-music-studios">BBC Music Studios</a> are due to open in 2027. Art, design, dance, fashion and music – welcome to London’s 21st-century culturopolis.</p><p>This once-neglected area of London – “a place where fridges went to die” as Gus Casely-Hayford, the director of V&amp;A East, <a href="https://www.thetimes.com/culture/art/article/v-a-east-stratford-review-new-opening-72tsbr70s?eafs_enabled=false">put it</a> – has been transformed into a creative mecca. But in many parts of the UK the story is one of falling visitor numbers, job losses and the closure of much-loved music venues and art spaces. These architectural palaces are a far cry from many of the crumbling theatres and museums outside the capital (and their well-maintained European equivalents).</p><p><em><strong>Do you have an opinion on the issues raised in this article? If you would like to submit a response of up to 300 words by email to be considered for publication in our<a href="https://www.theguardian.com/tone/letters"> letters</a> section, please <a href="mailto:guardian.letters@theguardian.com?body=Please%20include%20your%20name,%20full%20postal%20address%20and%20phone%20number%20with%20your%20letter%20below.%20Letters%20are%20usually%20published%20with%20the%20author%27s%20name%20and%20city/town/village.%20The%20rest%20of%20the%20information%20is%20for%20verification%20only%20and%20to%20contact%20you%20where%20necessary.">click here</a>.</strong></em></p> <a href="https://www.theguardian.com/commentisfree/2026/apr/17/the-guardian-view-on-a-much-needed-boost-for-the-arts-rebuilding-englands-cultural-landscape">Continue reading...</a>', '2026-04-18T04:46:50-05:00', 59520000);
