INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/18/a-prickle-of-hedgehogs-and-an-armada-of-newts-wildlife-settles-in-at-londons-new-queen-elizabeth-garden', 'A prickle of hedgehogs and an armada of newts: wildlife settles in at London’s new Queen Elizabeth garden', '2026-04-18T10:00:11+00:00', '<p>A former horticultural nursery in Regent’s Park has been transformed into a diverse mix of habitats, with a wide range of species already spotted ahead of its opening to the public on April 27</p><p>When the <a href="https://www.royalparks.org.uk/visit/parks/regents-park-primrose-hill/queen-elizabeth-ii-garden">Queen Elizabeth II garden</a> opens in Regent’s Park this month, the first people to visit the Royal Parks’ £5m biodiversity project will quickly discover they are not, in fact, the first visitors.</p><p>That honour belongs to a hairy-footed flower bee, a breeding pair of geese, some dragonfly nymphs, a flock of grey wagtails, a prickle of hedgehogs, an armada of newts, a flutter of spring butterflies and a “very cheeky” fox.</p> <a href="https://www.theguardian.com/environment/2026/apr/18/a-prickle-of-hedgehogs-and-an-armada-of-newts-wildlife-settles-in-at-londons-new-queen-elizabeth-garden">Continue reading...</a>', '2026-04-18T05:03:17-05:00', 186000);
