INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/us-catholics-trump-pope', '‘It’s kind of a tough situation’: US Catholics torn in feud between president and the pope', '2026-04-18T10:00:10+00:00', '<p>Trump’s attacks on Pope Leo XIV polarizing the diverse community as faith and politics come to a head</p><p>Maryellen Lewicki meets once a week for Bible study with a group of Catholic women in Decatur, Georgia, in a space they try to keep clear of politics. But Donald Trump’s name arises nonetheless.</p><p>“We have one person that we pray for during the course of the week,” she said. “What my friend said is that she prays for the president every day, that God will remove that hard heart of his and replace it with a softer one that has love.”</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/us-catholics-trump-pope">Continue reading...</a>', '2026-04-18T05:06:22-05:00', 372000);
