INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/18/is-meghan-markle-really-the-most-trolled-person-in-the-world', 'Is Meghan Markle really the most trolled person in the world? | Arwa Mahdawi', '2026-04-18T10:00:10+00:00', '<p> I have a lot of sympathy for Meghan but, at times, I do think that the Duchess of Sussex could do with putting her trials and tribulations in perspective</p><p>Iran may have <a href="https://www.theguardian.com/business/2026/apr/17/oil-gas-prices-fall-iran-strait-of-hormuz-brent-crude-donald-trump">reopened</a> the strait of Hormuz, but a global <a href="https://apnews.com/article/iran-war-europe-jet-fuel-flight-cancellations-birol-6e67fafd493861b3858de5548aa77703">energy crisis</a> has not yet been averted. The war has already damaged as much as <a href="https://www.cnbc.com/2026/04/15/iran-war-energy-facilities-refinery-pipeline-lng.html">$58bn worth</a> of power infrastructure. Even under the best-case circumstances, these could take years to repair.</p><p>Luckily, I think I’ve got a way to get us out of this mess. First we invent some sort of large suction device (technical details to be worked out later). Then we turn it on and hoover up all the rage directed at the Duchess of Sussex. Boom, energy crisis solved.</p><p>Arwa Mahdawi is a Guardian US columnist</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/18/is-meghan-markle-really-the-most-trolled-person-in-the-world">Continue reading...</a>', '2026-04-18T05:09:31-05:00', 564000);
