INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/money/2026/apr/18/maternity-pay-mortgage-struggle-self-employed', 'The maternity and mortgage struggle of being self-employed: ‘It was overwhelming at times’', '2026-04-18T11:00:11+00:00', '<p>Buying a house or having a baby has turned into a financial nightmare for those who are their own boss</p><p>Harriett Thompson started her maternity leave at the beginning of 2025, but at the start of this month she still had not received any of the statutory pay she was entitled to.</p><p>The freelance makeup artist described what she says is a familiar experience for a lot of self-employed mothers. “Luckily [my partner] Alex started a long contract when our daughter was born, which has enabled us to get by … That’s coming to an end now, with no future work in sight, so I’m getting anxious about receiving the money,” she told us.</p> <a href="https://www.theguardian.com/money/2026/apr/18/maternity-pay-mortgage-struggle-self-employed">Continue reading...</a>', '2026-04-18T06:05:21-05:00', 312000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/e-bike-crashes-safety-regulations', 'As e-bike crashes send an increasing number of people to the hospital, cities search for solutions', '2026-04-18T11:00:12+00:00', '<p>Cities look to registration, regulation and infrastructure improvement to cut number of e-bike injuries and deaths</p><p>The increasing number of traumatic injuries from e-bikes in the United States has caught the attention of physicians, lawmakers, pedestrians and others.</p><p>While there is a shared concern about people recklessly riding the trendy machines, there are significant differences among roadway safety advocates about the best ways to prevent accidents – including whether the government should focus on improving infrastructure rather than regulating e-bikes.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/e-bike-crashes-safety-regulations">Continue reading...</a>', '2026-04-18T06:05:21-05:00', 312000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/iran-war-bets-ethics-concerns', 'Traders placed over $1bn in perfectly timed bets on the Iran war. What is going on?', '2026-04-18T11:00:12+00:00', '<p>Suspicious wagers on the US-Israel war in Iran are creating huge windfalls and raising concerns among lawmakers</p><p>Sixteen bets made $100,000 each accurately predicting the timing of the US airstrikes against Iran on 27 February. Later, a single user would make over $550,000 after betting that Ayatollah Ali Khamenei would topple, just moments before his assassination by Israeli forces. On 7 April, right before Donald Trump announced a temporary ceasefire with Iran, traders bet $950m that oil prices would come down. They did.</p><p>These bets and other well-timed wagers accurately predicted the precise timing of major developments in the US-Israel war with Iran, creating huge windfalls and raising concerns among lawmakers and experts over potential insider trading.</p> <a href="https://www.theguardian.com/world/2026/apr/18/iran-war-bets-ethics-concerns">Continue reading...</a>', '2026-04-18T06:05:21-05:00', 312000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/science/video/2026/apr/11/astronauts-back-on-earth-artemis-ii-crew-splashes-down-after-record-breaking-moon-flyby-video', '''Astronauts back on Earth'': Artemis II crew splashes down after record-breaking moon flyby – video', '2026-04-11T08:14:07+00:00', '<p>The Artemis II, and the four astronauts aboard the Orion space capsule, splashed down into the Pacific Ocean off the coast of San Diego on Friday night, with all four astronauts in good health. Commander Reid Wiseman, pilot Victor Glover and mission specialist Christina Koch of Nasa, and the Canadian Space Agency’s Jeremy Hansen, have just become the first humans to travel to the moon, and return to Earth safely, since the crew of Apollo 17 in December 1972</p><ul><li><p><a href="https://www.theguardian.com/science/2026/apr/10/artemis-ii-landing-return-moon-mission">‘Just the beginning’: Artemis II crew splashes down after record-breaking moon flyby</a></p></li><li><p><a href="https://www.theguardian.com/science/gallery/2026/apr/11/artemis-ii-splashdown-in-pictures">Artemis II splashdown! – in pictures</a></p></li></ul> <a href="https://www.theguardian.com/science/video/2026/apr/11/astronauts-back-on-earth-artemis-ii-crew-splashes-down-after-record-breaking-moon-flyby-video">Continue reading...</a>', '2026-04-18T06:06:24-05:00', 612000000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/earth-brightness-study', 'Earth gets brighter every year but progression is volatile, study finds', '2026-04-18T11:00:11+00:00', '<p>Covid, light pollution regulations and faltering global economy affect location and intensity of brightness</p><p>Earth continues to get brighter every year, researchers have found, but the location and intensity of the progression has become increasingly volatile because of Covid-19, regulations on light pollution, and a faltering global economy.</p><p>Nasa-funded researchers at the University of Connecticut (UConn) studied more than 1.1m satellite images taken over a nine-year period to establish that the planet’s artificial light <a href="https://www.nature.com/articles/s41586-026-10260-w#Sec1">increased by a net 16%</a> between 2014 and 2022.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/earth-brightness-study">Continue reading...</a>', '2026-04-18T06:06:24-05:00', 372000);
