INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/18/trump-pope-war-morals', 'War isn’t a ‘moral’ issue – at least not for the Trump administration | Dave Schilling', '2026-04-18T11:00:12+00:00', '<p>The US president’s grudge match with the pope underlines how religion really functions in American politics</p><p>I’m not a particularly religious person, even though everyone tells me how cool believing in God is now. Every so often, we get a new trend piece about how rad and chill Christianity has become. <em>All the skateboarders and chads are churchmaxxing. Only atheists wear skinny jeans any more. Christopher Hitchens would totally get mogged by Pat Robertson.</em> Personally, I don’t buy it. Influencers like Logan Paul and IShowSpeed aren’t going on Twitch to tell their viewers to tithe 10% of their earnings to the Lord. They’re encouraging them to buy cases and cases of Prime Hydration Drink and watch WrestleMania.</p><p>In my research on the topic, I found <a href="https://www.the-independent.com/life-style/church-christianity-gen-z-young-people-faith-god-easter-b2734957.html">this article from the Independent</a> this year that claims that gen Z is, like, totally down with Christ and can’t wait to chug Mountain Dew with their local pastor in a musty basement. No sooner had I clicked the link than I found an editor’s note that the poll that supported the claim was <a href="https://www.the-independent.com/news/uk/home-news/church-poll-christianity-yougov-fraud-b2946307.html">found to be fraudulent</a>.</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/18/trump-pope-war-morals">Continue reading...</a>', '2026-04-18T06:09:32-05:00', 564000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/hungary-peter-magyar-donald-tusk-poland-europe', 'Hungary’s incoming PM seeks Polish help to renew EU relations', '2026-04-18T11:00:12+00:00', '<p>Péter Magyar hopes building stronger relations with Poland will help restore ties with bloc after Orbán’s rule</p><p>The Hungarian election winner, Péter Magyar, is eyeing a special relationship with Poland’s prime minister, Donald Tusk to draw on the neighbouring country’s experience of repairing relations with the EU after years of illiberal rule.</p><p>Since 1989, the two countries have seemingly shared parallels in their paths. Now the two centre-right, pro-European leaders preside over the tricky task of restoring the rule of law and improving state institutions after years of democratic backsliding and clashes with the EU.</p> <a href="https://www.theguardian.com/world/2026/apr/18/hungary-peter-magyar-donald-tusk-poland-europe">Continue reading...</a>', '2026-04-18T06:14:46-05:00', 876000);
