INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/18/growing-knowledge-growing-yield-british-wine-making-comes-of-age', 'Growing knowledge, growing yield: British wine-making comes of age', '2026-04-18T12:00:13+00:00', '<p>Changing climate, new techniques and a homegrown study programme have all helped drive a UK viticulture boom</p><p>Rows of vines stretch across the rolling hills of rural Dorset. Currently waist height, they appear bare against a bleak spring sky. Up close, you can see they are already dotted with tiny woolly buds as they exit their winter dormancy for a new growth cycle.</p><p>Come summer these rows will be laden with chardonnay, pinot noir and pinot meunier grapes, ready to make the latest batch of English sparkling wine from the Langham estate near Dorchester.</p> <a href="https://www.theguardian.com/business/2026/apr/18/growing-knowledge-growing-yield-british-wine-making-comes-of-age">Continue reading...</a>', '2026-04-18T07:02:52-05:00', 162000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/18/survivors-alleged-sexual-abuse-former-owner-of-harrods-mohamed-al-fayed', 'Survivors of alleged sexual abuse by former owner of Harrods want enablers to face justice', '2026-04-18T12:00:12+00:00', '<p>Justice for Fayed and Harrods Survivors group claim there are ‘dozens of individuals who must be held to account’</p><p>A group of 50 survivors of alleged sexual abuse by Harrods’ former owner Mohamed Al Fayed are calling for “meaningful consequences” for those who they claim facilitated and ignored the abuse.</p><p>“If they think the money is the important factor they are so far off the mark,” said Jen Mills, a member of the Justice for Fayed and Harrods Survivors group. They claim there are “dozens of individuals who must be held to account”, from a range of eras.</p> <a href="https://www.theguardian.com/business/2026/apr/18/survivors-alleged-sexual-abuse-former-owner-of-harrods-mohamed-al-fayed">Continue reading...</a>', '2026-04-18T07:08:03-05:00', 474000);
