INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('bbc', 'General', 'https://www.bbc.com/news/videos/ckgepkp3zgjo#2', 'What does it take to survive in the Arctic? These rangers have an idea', '2026-04-17T23:01:43+00:00', 'The BBC spent time with the Canadian military in the country''s northernmost region - this is what they taught us about dealing with extreme conditions.', '2026-04-18T07:09:44-05:00', 47280000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/lifeandstyle/2026/apr/18/gross-ingredients-16-favourite-foods-cockroach-coffee', 'Help, there’s a cockroach in my coffee! 16 gross ingredients hidden in your favourite foods', '2026-04-18T11:00:12+00:00', '<p>From wood pulp in ice-cream to peat in portobellos, science has transformed how we dine. Do you know exactly what’s lurking in the grub we eat?</p><p>Microbial slime and a side helping of sand doesn’t sound like much of a meal, but a startling amount of the food we eat today contains ingredients that are, at the very least, unexpected – and, at worst, dangerous, such as heavy metals from polluted soils.</p><p>Then there is the thorny question of what ultra‑processed foods in our diets might be doing to us. “While each food additive, so‑called processing aid, fortificant and unrecognisably modified ingredient has been tested individually and declared safe, are they really?” asks Chris Young, who runs the Real Bread Campaign for <a href="https://www.sustainweb.org/">Sustain</a>, the alliance for better food and farming, and was named joint winner of Slow Food In The UK’s 2025 person of the year award. “The studies are relatively small and short, leaving history littered with additives that we were once promised would not harm us but were later withdrawn or banned on health grounds. What might the long-term effect be of eating such substances, individually or in the cocktails created for each product and across our shopping baskets?”</p> <a href="https://www.theguardian.com/lifeandstyle/2026/apr/18/gross-ingredients-16-favourite-foods-cockroach-coffee">Continue reading...</a>', '2026-04-18T07:10:09-05:00', 4140000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/14/windfarm-reality-green-jobs-boom-englands-east-coast-unemployment', 'Surrounded by windfarms but out of work: the reality of the green jobs boom on England’s east coast', '2026-04-14T07:00:03+00:00', '<p>The government hails the ‘green revolution’ as a solution to economic decline, but some young jobseekers say the rhetoric does not match their experience</p><p>On paper, Jake Snell, 19, sounds like the perfect candidate for a role in the UK’s burgeoning green energy sector. He has high grades in maths and physics A-level, a distinction in BTec engineering and another distinction in an extended engineering diploma. He has also done work experience at an engineering company.</p><p>He is from Lowestoft, a coastal town in Suffolk, outside Great Yarmouth. Both towns contain <a href="https://www.healthysuffolk.org.uk/asset-library/JSNA/Indices-of-Deprivation-2025-Suffolk-summary.pdf">areas that fall within</a> the <a href="https://www.ons.gov.uk/visualisations/dvc1371/#/E07000145">most deprived 20%</a> in England and are part of a wider pattern of <a href="https://www.theguardian.com/environment/2025/jul/07/young-people-uk-coast-mental-health-coastal-communities-deprivation">coastal places with low employment</a> opportunities.</p> <a href="https://www.theguardian.com/environment/2026/apr/14/windfarm-reality-green-jobs-boom-englands-east-coast-unemployment">Continue reading...</a>', '2026-04-18T07:12:15-05:00', 363600000);
