INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/iran-closes-strait-of-hormuz-again-until-us-lifts-blockade', 'Iran closes strait of Hormuz again ‘until US lifts blockade’', '2026-04-18T12:47:34+00:00', '<p>IRGC reportedly fires on tanker as it tries to pass through strait during brief window when shipping lane had reopened</p><ul><li><p><a href="https://www.theguardian.com/world/2026/apr/18/donald-trump-tehran-war-mismanaged-posts-progress-peace">Analysis: Trump and Tehran’s series of mismanaged posts stall progress towards peace</a> </p></li></ul><p>Iranian officials say they have reversed the reopening of the strait of Hormuz and reimposed restrictions on the vital shipping lane after the US said it would not end its blockade of Iranian ports.</p><p>A UK maritime agency reported that Islamic Revolutionary Guard Corps (IRGC) ships had fired at a tanker as it attempted to pass through the strait on Saturday. Reuters reported an Indian-flagged vessel carrying crude oil had also been attacked while in the waterway.</p> <a href="https://www.theguardian.com/world/2026/apr/18/iran-closes-strait-of-hormuz-again-until-us-lifts-blockade">Continue reading...</a>', '2026-04-18T07:52:28-05:00', 294000);
