INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('npr', 'General', 'https://www.npr.org/sections/the-picture-show/2026/04/18/nx-s1-5766110/overfishing-in-southeast-asia', 'Photos: How overfishing in Southeast Asia is an ecological and human crisis', '2026-04-18T09:00:00-04:00', 'A rare look at one of the world&apos;s most critical and understudied environmental crises. Southeast Asia produces more than half of the world&apos;s fish, yet its waters are among the most depleted and contested.', '2026-04-18T08:02:01-05:00', 120000);
