INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/trump-pope-norman-vincent-peale', 'Trump’s antipathy for Pope may have roots in childhood Protestant church', '2026-04-18T13:00:14+00:00', '<p>Manhattan church led by Norman Vincent Peale was known for opposing presidency of JFK – and Catholics in general</p><p><a href="https://www.theguardian.com/us-news/donaldtrump">Donald Trump</a>’s attacks this week on <a href="https://www.theguardian.com/world/pope-leo-xiv">Pope Leo</a>, for his criticism of the US attack on Iran and the US president’s decision to post an image portraying himself as Jesus Christ on social media, make a good deal more sense considering Trump attended services as a young man at the Protestant Marble Collegiate church in Manhattan, which was led at the time by an anti-Catholic pastor.</p><p>That church’s pastor in Trump’s youth, Norman Vincent Peale, who would later officiate at Trump’s first wedding, is best-known today as the author of the Christian self-help book The Power of Positive Thinking, but when Trump was 14, Peale made national headlines as the leader of a group of Protestant churchmen who loudly objected to the presidential candidacy of John F Kennedy, on the grounds that he was a Catholic.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/trump-pope-norman-vincent-peale">Continue reading...</a>', '2026-04-18T08:06:50-05:00', 396000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/venice-flood-barrier-plan-b-rising-sea-level', '‘We can’t wait’: Venice already seeking floods plan B five years after barriers’ launch', '2026-04-18T13:00:14+00:00', '<p>Rising sea levels and ecological damage caused by heavy use of flood defence system force city authorities to consider next move</p><p>The Arsenale, the colossal shipyard that was the engine of the Venetian Republic’s domination for seven centuries, remains the nucleus of the city’s control over the water. Its northern section is made up of cavernous brick warehouses called <em>capannoni</em>, which in the 16th century could produce a warship a day through a rigorously ordered assembly line.</p><p>Now, one of them houses the operations centre of the Mose, the sprawling flood defence system that protects the city.</p> <a href="https://www.theguardian.com/world/2026/apr/18/venice-flood-barrier-plan-b-rising-sea-level">Continue reading...</a>', '2026-04-18T08:06:50-05:00', 396000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/18/franco-manca-sourdough-pizza-craze', 'As Franco Manca scales back, is the air going out of the sourdough pizza craze?', '2026-04-18T13:00:13+00:00', '<p>The restaurant is to cut more than a fifth of its outlets amid an onslaught from supermarkets and rival chains</p><p>When Franco Manca first opened in south London’s Brixton Market in 2008, its competitively priced sourdough pizzas served in a sophisticated setting quickly <a href="https://www.theguardian.com/lifeandstyle/2008/sep/21/restaurants.foodanddrink1">drew a buzz</a>.</p><p>“It was all the rage,” says food<strong> </strong>blogger Gerry del Guercio<strong> </strong>of<strong> </strong><a href="https://www.instagram.com/bitetwicefoodreviews/">BiteTwice</a>,<strong> </strong>who visited in the early days and recalls the novelty of seeing queues forming for pizza in London. “It was just desperately cool, and everyone wanted to try.”</p> <a href="https://www.theguardian.com/business/2026/apr/18/franco-manca-sourdough-pizza-craze">Continue reading...</a>', '2026-04-18T08:14:09-05:00', 834000);
