INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/trump-administration-white-house-ballroom', 'Trump administration cleared to continue construction of White House ballroom, court rules', '2026-04-18T13:37:12+00:00', '<p>Construction was stopped after suit challenged president’s authority to raze East Wing without congressional approval</p><p>The <a href="https://www.theguardian.com/us-news/trump-administration">Trump administration</a> can continue building a $400m White House ballroom at the site of the former East Wing, a US appeals court <a href="https://media.cadc.uscourts.gov/orders/docs/2026/04/26-5123LDSN.pdf">ruled on Friday</a>.</p><p>The three-judge panel of the US court of appeals for Washington DC granted the administration a stay of an order days earlier that had aimed to <a href="https://www.courtlistener.com/docket/72028010/73/national-trust-for-historic-preservation-in-the-united-states-v-national/">halt</a> most aboveground construction. That earlier order had resulted from a lawsuit filed by the National Trust for Historic Preservation, which <a href="https://www.theguardian.com/us-news/2026/mar/31/judge-blocks-trump-white-house-ballroom-plan">challenged whether</a> Donald Trump had the authority to raze the East Wing and construct the ballroom without congressional approval.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/trump-administration-white-house-ballroom">Continue reading...</a>', '2026-04-18T08:50:19-05:00', 786000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('wsj', 'General', 'WP-WSJ-0003290964', 'Meet the Inventor Dubbed &#x2018;Black Edison,&#x2019; Who Beat Thomas Edison in Court', '2026-04-18T14:00:00+00:00', 'In the 1880s, Granville T. Woods won patent battles to protect his inventions, including a system to allow moving trains to communicate wirelessly.', '2026-04-18T09:03:25-05:00', 204000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/film/2026/apr/17/hollywood-big-screen-imax', 'Screenmaxxing: why Hollywood is supersizing the big screen experience', '2026-04-17T16:58:46+00:00', '<p>With Imax more popular than ever, a new way to watch movies – HDR by Barco – has been quietly rolling out but what difference does it really make?</p><p>At this year’s CinemaCon, an annual gathering where film studios show off their upcoming wares to excite the exhibitors they hope to showcase them, Disney announced a new way to see a movie, sort of: <a href="https://deadline.com/2026/04/disney-infinity-vision-premium-theatrical-experience-1236863864/">InfinityVision</a>. Despite the cutesy Marvelized name, it’s not a superhero-specific experience; it’s a certification for premium large-format (PLF) auditoriums. The idea is that any InfinityVision-certified screen will adhere to or exceed standards – vaguely described so far – in size, sound quality, and picture brightness/clarity. There are supposedly 300 such screens already certified around the globe, though there doesn’t seem to be an actual list explaining which ones they are yet.</p><p>The practical reason for this additional layer of branding is that Disney’s Avengers: Doomsday is premiering in December on the same weekend as the third Dune movie, which has a deal to occupy coveted (and limited) Imax screens for several weeks. This essentially locks Earth’s mightiest heroes out of one of the marquee names in exhibition; InfinityVision seems intended to reassure viewers that their other options, presumably the various Dolby, RPX, and other branded PLF auditoriums that already exist, are as impressive as possible. Call it screenmaxxing.</p> <a href="https://www.theguardian.com/film/2026/apr/17/hollywood-big-screen-imax">Continue reading...</a>', '2026-04-18T09:07:53-05:00', 76140000);
