INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/new-york-respond-santacon-fraud-indictment', 'Just what they wanted: fed-up New Yorkers revel in SantaCon fraud charge', '2026-04-18T14:00:15+00:00', '<p>The pub crawl’s organizer is accused of pocketing donations but residents and businesses have long had misgivings</p><p>On what started as an otherwise uneventful spring day in New York City, thousands of residents last week received what they felt was an early Christmas present.</p><p>Stefan Pildes, organizer of <a href="https://www.theguardian.com/us-news/2021/dec/09/santacon-new-york-debauchery-charity">SantaCon</a> in New York City, was <a href="https://www.justice.gov/usao-sdny/pr/santacon-organizer-charged-wire-fraud-scheme-targeting-attendees-and-host-venues">arrested </a>on Wednesday morning for allegedly using hundreds of thousands from event-based charitable donations on his personal expenses, such as luxe vacations and “extravagant meals”, Manhattan federal prosecutors said.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/new-york-respond-santacon-fraud-indictment">Continue reading...</a>', '2026-04-18T09:12:04-05:00', 708000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/technology/2026/apr/18/sam-altman-house-attack-ai', 'How a fiery attack on Sam Altman’s home unfolded', '2026-04-18T14:00:15+00:00', '<p>Molotov cocktail attack on OpenAI CEO’s home comes amid growing discontent against artificial intelligence</p><p>In the early hours of 10 April, a man approached the gate of <a href="https://www.theguardian.com/technology/openai">OpenAI</a> CEO <a href="https://www.theguardian.com/technology/sam-altman">Sam Altman</a>’s house in San Francisco and <a href="https://www.theguardian.com/technology/2026/apr/10/sam-altman-home-molotov-cocktail">hurled</a> a molotov cocktail at the building before fleeing. The suspect, 20-year-old Daniel Moreno-Gama, was arrested less than two hours<strong> </strong>later while allegedly attempting to break into the headquarters of OpenAI with a jug of kerosene, a lighter and an anti-AI manifesto.</p><p>Federal and California state authorities have <a href="https://www.theguardian.com/us-news/2026/apr/13/sam-altman-openai-man-charged">charged</a> Moreno-Gama with a range of crimes including attempted arson and attempted murder. His parents issued a statement this week saying that their son had recently suffered a mental health crisis. Moreno-Gama, who has not yet entered a plea, faces up to life in prison if convicted.</p> <a href="https://www.theguardian.com/technology/2026/apr/18/sam-altman-house-attack-ai">Continue reading...</a>', '2026-04-18T09:18:19-05:00', 1086000);
