INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/trump-psychedelic-drugs-executive-order', 'Trump announces reforms to accelerate access to psychedelic drug treatments', '2026-04-18T15:03:54+00:00', '<p>President signed executive order directing FDA to expedite review of psychedelic drugs including ibogaine</p><p><a href="https://www.theguardian.com/us-news/donaldtrump">Donald Trump</a> on Saturday announced reforms intended to speed up access to medical research and treatment based on psychedelic drugs.</p><p>The president signed an executive order directing the federal Food and Drug Administration (FDA) to expedite review of drugs such as ibogaine, which US military veteran groups have said can help treat <a href="https://www.theguardian.com/society/post-traumatic-stress-disorder">post-traumatic stress disorder</a>.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/trump-psychedelic-drugs-executive-order">Continue reading...</a>', '2026-04-18T10:06:45-05:00', 174000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/donald-trump-tehran-war-mismanaged-posts-progress-peace', 'Trump and Tehran’s series of mismanaged posts stall progress towards peace', '2026-04-18T15:04:47+00:00', '<p>US president’s desperation for war to end has seen him trying to speed through a process he does not fully control</p><p>A set of mismanaged and premature media announcements by Donald Trump and Tehran has led to the collapse of progress towards a peace settlement between Iran and the US.</p><p>The recent missteps ended with Iran saying it would <a href="https://www.theguardian.com/world/2026/apr/18/iran-closes-strait-of-hormuz-again-until-us-lifts-blockade">reinstate a complete block on the movement of commercial shipping through the strait of Hormuz</a> and that it would not allow any of its stockpile of highly enriched uranium to be exported out of the country.</p> <a href="https://www.theguardian.com/world/2026/apr/18/donald-trump-tehran-war-mismanaged-posts-progress-peace">Continue reading...</a>', '2026-04-18T10:06:45-05:00', 120000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/business/2026/apr/18/reeves-rightly-fears-the-bond-market-but-she-can-afford-to-ditch-one-unhelpful-rule', 'Reeves rightly fears the bond market, but she can afford to ditch one unhelpful rule | Phillip Inman', '2026-04-18T15:00:16+00:00', '<p>The chancellor has wisely vowed to drive down the annual deficit, but long-term defence investment must not be delayed</p><p>There is a good reason Rachel Reeves is wary of the <a href="https://www.theguardian.com/business/2023/oct/26/ghastly-expensive-mess-bond-vigilantes-return-as-deficits-rise">dreaded bond market vigilantes</a>. Anyone who inherits a mountain of debt and then finds out that many of the lenders act like sharks is right to be concerned.</p><p>Most of the participants in financial markets are not actively predatory. They swim in a sea of money with only one rule, to stick together, hoovering up as much profit as they can at the lowest risk.</p> <a href="https://www.theguardian.com/business/2026/apr/18/reeves-rightly-fears-the-bond-market-but-she-can-afford-to-ditch-one-unhelpful-rule">Continue reading...</a>', '2026-04-18T10:18:17-05:00', 1080000);
