INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/politics/2026/apr/18/starmer-would-have-blocked-mandelson-role-over-vetting-failure-says-lammy', 'Starmer would have blocked Mandelson role over vetting failure, says Lammy', '2026-04-18T18:44:35+00:00', '<p>Deputy prime minister says it is ‘inexplicable’ top civil servant kept Downing Street in dark</p><p>Keir Starmer would have blocked Peter Mandelson from serving as the UK’s ambassador to Washington had he known <a href="https://www.theguardian.com/politics/2026/apr/17/what-happens-security-vetting-peter-mandelson">he failed security vetting</a>, David Lammy has said, as he attempted to shore up the prime minister amid damaging fallout from the row.</p><p>In his first public comments on the vetting affair, Lammy said it was “inexplicable” that Oliver Robbins, the former top civil servant who was forced out of the Foreign Office this week, had opted to leave Downing Street in the dark over the outcome.</p> <a href="https://www.theguardian.com/politics/2026/apr/18/starmer-would-have-blocked-mandelson-role-over-vetting-failure-says-lammy">Continue reading...</a>', '2026-04-18T13:45:53-05:00', 78000);
