INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/australia-news/2026/apr/19/energy-for-australians-accepted-1m-coal-australia-independent-claims', '‘Independent’ group Energy for Australians that ran anti-Labor ads received more than $1m from coal lobby', '2026-04-18T20:00:22+00:00', '<p>Coal Australia denies its donations to the ‘community-driven association’ amount to astroturfing, but critics accuse the group of misleading the public</p><ul><li><p><a href="https://www.theguardian.com/australia-news/live/2026/apr/19/australia-news-live-free-public-transport-in-victoria-extended-man-charged-with-in-nsw-ntwnfb">Follow our Australia news live blog for latest updates</a></p></li><li><p>Get our <a href="https://www.theguardian.com/email-newsletters?CMP=cvau_sfl">breaking news email</a>, <a href="https://app.adjust.com/w4u7jx3">free app</a> or <a href="https://www.theguardian.com/australia-news/series/full-story?CMP=cvau_sfl">daily news podcast</a></p></li></ul><p>An “independent, community-driven association” that ran anti-Labor adverts during the last federal election was entirely funded by a coal industry lobby group, the Guardian can reveal.</p><p>Energy for Australians accepted more than $1m from Coal Australia – a group advocating for coal whose members include major miners Yancoal, Peabody, New Hope and Whitehaven.</p> <a href="https://www.theguardian.com/australia-news/2026/apr/19/energy-for-australians-accepted-1m-coal-australia-independent-claims">Continue reading...</a>', '2026-04-18T15:07:44-05:00', 444000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/environment/2026/apr/19/australia-emissions-increasing-coalmines-climate-policy-analysis', 'Australia’s coalmine emissions are increasing. Is this how a major policy to cut climate pollution is meant to work?', '2026-04-18T20:00:22+00:00', '<p>The Albanese government overhauled policy and promised significant pollution cuts – but carbon offsets are still being used as an excuse</p><ul><li><p><a href="https://www.theguardian.com/environment/2025/mar/10/sign-up-for-the-clear-air-australia-environment-newsletter-with-adam-morton?CMP=cvau_sfl">Sign up for climate and environment editor Adam Morton’s free Clear Air newsletter here</a></p></li></ul><p>Is this how a national scheme to cut climate pollution is supposed to work?</p><p>Australian government data <a href="https://cer.gov.au/markets/reports-and-data/safeguard-data">released this week</a> shows emissions from Australian coalmines increased last financial year. About 80% of the coalmines pumped more into the atmosphere than their government-imposed limit.</p><p><strong><a href="https://www.theguardian.com/environment/2025/mar/10/sign-up-for-the-clear-air-australia-environment-newsletter-with-adam-morton?CMP=copyembed">Sign up to get climate and environment editor Adam Morton’s Clear Air column as a free newsletter</a></strong></p> <a href="https://www.theguardian.com/environment/2026/apr/19/australia-emissions-increasing-coalmines-climate-policy-analysis">Continue reading...</a>', '2026-04-18T15:07:44-05:00', 444000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/commentisfree/2026/apr/19/birdwatching-hobby-pokemon-generation', 'I adored Pokémon as a child. Now I collect critters of a different kind in a hobby I’m uniquely suited to – birdwatching  | Jayce Carrano', '2026-04-18T20:00:22+00:00', '<p>Every player has experienced that fierce loyalty to one pocket monster or another. The same is true here</p><p>The Pokémon franchise has turned 30, which means that it’s been a long time since a childhood friend and I braved Pokémon Blue’s haunted Lavender Town together – solemnly handing the Game Boy back and forth in the first (and perhaps last) documented case of two only children sharing something.</p><p>For most of my 29 years, I couldn’t have cared less about birdwatching. But as it turns out, this hobby is uniquely suited to those of us who belong to the Pokémon generation.</p> <a href="https://www.theguardian.com/commentisfree/2026/apr/19/birdwatching-hobby-pokemon-generation">Continue reading...</a>', '2026-04-18T15:07:44-05:00', 444000);
INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/world/2026/apr/18/terrorist-attack-kyiv-ukraine', 'Investigators examine whether Ukraine terrorist attack was directed by Russia', '2026-04-18T20:19:53+00:00', '<p>The gunman, who killed six people in Kyiv before police shot him dead, was a Ukrainian citizen born in Moscow</p><p>Ukrainian investigators are examining whether a terrorist attack in Kyiv was directed by Moscow after a man shot dead six people on Saturday before he was killed by police.</p><p>The gunman, 58, opened fire on passersby before barricading himself in a supermarket and taking hostages. Detectives sealed off the area in the Holosiivskyi district and tried to negotiate with him. He refused and was killed after a 40-minute standoff.</p> <a href="https://www.theguardian.com/world/2026/apr/18/terrorist-attack-kyiv-ukraine">Continue reading...</a>', '2026-04-18T15:21:40-05:00', 108000);
