INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/united-plane-emergency-landing-pittsburgh', 'United plane makes emergency landing in Pittsburgh over ‘possible security issue’', '2026-04-18T20:30:44+00:00', '<p>Passengers on flight from Chicago to New York exited via slides as FBI, bomb technicians and K-9 unit responded  </p><ul><li><p><a href="https://www.theguardian.com/news/2026/feb/17/sign-up-for-the-breaking-news-us-email-to-get-newsletter-alerts-direct-to-your-inbox?utm_medium=ACQUISITIONS_STANDFIRST&amp;utm_campaign=BN22326&amp;utm_content=signup&amp;utm_term=standfirst&amp;utm_source=GUARDIAN_WEB">Sign up for the Breaking News US email to get newsletter alerts in your inbox</a></p></li></ul><p>A United Airlines flight bound for New York City was forced to land and evacuate in Pittsburgh on Saturday morning after crew members reported a “possible security issue”, a spokesperson for the Federal Aviation Administration said.</p><p>United flight 2092 took off from Chicago O’Hare airport and had been en route to LaGuardia airport in New York. The plane diverted to Pittsburgh international airport as a result of the reported threat.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/united-plane-emergency-landing-pittsburgh">Continue reading...</a>', '2026-04-18T15:38:17-05:00', 456000);
