INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/sport/2026/apr/18/alycia-baumgardner-caroline-dubois-fight-katie-taylor-boxing', '‘That’s a guppy’: Baumgardner swats aside Britain’s Dubois as feud escalates', '2026-04-18T20:49:00+00:00', '<ul><li><p>American dismisses Dubois as ‘not on my level’</p></li><li><p>Baumgardner targets bouts with Taylor or Serrano</p></li><li><p>British stablemate touts fight as ‘best versus best’</p></li></ul><p>A dismissive Alycia Baumgardner said Britain’s Caroline Dubois still has more to prove before the American will entertain a fight between the two unified champions.</p><p>That was the curt assessment from Baumgardner early Saturday morning after she <a href="https://www.theguardian.com/sport/2026/apr/18/alycia-baumgardner-fight-lani-daniels-shadasia-green-boxing">retained her WBA, WBO and IBF junior lightweight world titles</a> with a controlled, at times punishing display across 10 three-minute rounds against Bo Mi Re Shin in a main event that started well past midnight at Madison Square Garden.</p> <a href="https://www.theguardian.com/sport/2026/apr/18/alycia-baumgardner-caroline-dubois-fight-katie-taylor-boxing">Continue reading...</a>', '2026-04-18T16:00:07-05:00', 666000);
