INSERT OR IGNORE INTO articles (source, section, guid, title, pub_date, description, detected_at, latency_ms) VALUES ('guardian', 'General', 'https://www.theguardian.com/us-news/2026/apr/18/jon-ossoff-fiery-speech-presidential-rumors', 'Jon Ossoff calls out ‘Mar-a-Lago mafia’ amid presidential bid rumors', '2026-04-18T22:13:23+00:00', '<p>Georgia senator says Americans will pay for Trump’s Iran war, and family’s corruption, with child and health care cuts</p><p>At a campaign rally in Augusta, Georgia, on Saturday, the Democratic senator Jon Ossoff mocked <a href="https://www.theguardian.com/us-news/donaldtrump">Donald Trump</a>’s rosy predictions on Iran and tore into what he called the unprecedented corruption of the president’s family.</p><p>While Ossoff is running for re-election in November, he trained most of his fire on the president, and the vice-president, amid mounting speculation that the Democrat could launch a bid for his party’s nomination for the presidency in 2028.</p> <a href="https://www.theguardian.com/us-news/2026/apr/18/jon-ossoff-fiery-speech-presidential-rumors">Continue reading...</a>', '2026-04-18T17:18:48-05:00', 324000);
